    <input type={type} value={value} onChange={onChange} placeholder={placeholder}
      style={{width:"100%",padding:"11px 14px",borderRadius:10,
        border:`1px solid ${T.border}`,background:T.bgInput,fontSize:14,color:T.text}}/>
