/* ════════════════════════════════════════════════════════════════════════════
   HELPERS — alertas de pets
═══════════════════════════════════════════════════════════════════════════ */
const parseDate=(str)=>{if(!str)return null;const[d,m,y]=str.split("/").map(Number);return new Date(y,m-1,d);};
const daysUntil=(dateStr)=>{const d=parseDate(dateStr);if(!d)return null;const t=new Date();t.setHours(0,0,0,0);return Math.floor((d-t)/86400000);};
const daysSince=(dateStr)=>{const u=daysUntil(dateStr);return u===null?null:-u;};
const formatDays=(d)=>{if(d===null)return"";if(d<0)return`${-d}d atrás`;if(d===0)return"hoje";if(d===1)return"amanhã";if(d<7)return`em ${d}d`;if(d<30)return`em ${Math.floor(d/7)}sem`;return`em ${Math.floor(d/30)}m`;};
const alertLevel=(d)=>{if(d===null)return null;if(d<0)return"danger";if(d<=7)return"alert";return null;};

const getPetAlerts=(pet)=>{
  const a=[];
  pet.vacinas.forEach(v=>{const d=daysUntil(v.proxima);const lv=alertLevel(d);if(lv)a.push({tipo:"Vacina",nome:v.nome,dias:d,nivel:lv});});
  pet.vermifugos.forEach(v=>{const d=daysUntil(v.proxima);const lv=alertLevel(d);if(lv)a.push({tipo:"Vermífugo",nome:v.produto,dias:d,nivel:lv});});
  pet.antipulgas.forEach(v=>{const d=daysUntil(v.proxima);const lv=alertLevel(d);if(lv)a.push({tipo:"Antipulga",nome:v.produto,dias:d,nivel:lv});});
  return a.sort((a,b)=>a.dias-b.dias);
};
const getAllPetAlerts=(pets)=>{
  const all=[];
  pets.forEach(p=>{getPetAlerts(p).forEach(a=>all.push({...a,pet:p.nome,petId:p.id,foto:p.foto}));});
  return all.sort((a,b)=>a.dias-b.dias);
};

/* ════════════════════════════════════════════════════════════════════════════
   TELA HOJE — Dashboard sem hábitos
═══════════════════════════════════════════════════════════════════════════ */
function TelaHoje({agenda,pets,looks,makes,skDiario,skProdutos,sitioProjetos,casaTarefas,onMenu,onNavPet,onNav,nomeUsuario}){
  const hora=now.getHours();
  const cumprimento=hora<12?"Bom dia":hora<18?"Boa tarde":"Boa noite";
  const m = MASCOTES.hoje;
  const falaFlora = useMemo(()=>m.saudacoes[Math.floor(Math.random()*m.saudacoes.length)],[]);

  const alertasPets = getAllPetAlerts(pets).slice(0,3);

  // Camélia recomenda — escolhe uma sugestão de skincare com base no estado
  const camRecomenda = useMemo(()=>{
    if(skDiario.length===0) return {texto:"Que tal registrar uma nova foto da pele?",cta:"Ir para Skincare",emoji:"📸"};
    const ultimo = skDiario[skDiario.length-1];
    const diasUlt = daysSince(ultimo.data);
    if(diasUlt!==null && diasUlt>=12) return {texto:`Você não registra a pele há ${diasUlt} dias.`,cta:"Registrar foto",emoji:"📸"};
    // Tem produto há mais de 30 dias?
    const longo = skProdutos.find(p=>!p.fim && p.inicio && daysSince(p.inicio)>=30);
    if(longo) return {texto:`Já faz ${daysSince(longo.inicio)} dias usando ${longo.nome}.`,cta:"Ver evolução",emoji:"✨"};
    return {texto:"Vamos cuidar da pele hoje?",cta:"Ir para Skincare",emoji:"🧴"};
  },[skDiario,skProdutos]);

  // Memória do dia — escolhe uma foto aleatória do passado
  const memoriaDoDia = useMemo(()=>{
    const all=[];
    pets.forEach(p=>(p.galeria||[]).forEach(g=>{
      const d=parseDate(g.data); if(d) all.push({data:d,dataStr:g.data,foto:g.foto,tipo:"Pet",sub:p.nome});
    }));
    looks.forEach(l=>{const d=parseDate(l.data); if(d&&l.foto) all.push({data:d,dataStr:l.data,foto:l.foto,tipo:"Look",sub:l.titulo||l.ocasiao});});
    makes.forEach(mk=>{const d=parseDate(mk.data); if(d&&mk.foto) all.push({data:d,dataStr:mk.data,foto:mk.foto,tipo:"Make",sub:mk.titulo});});
    skDiario.forEach(s=>{const d=parseDate(s.data); if(d&&s.fotoFrontal) all.push({data:d,dataStr:s.data,foto:s.fotoFrontal,tipo:"Pele",sub:"Diário"});});
    sitioProjetos.forEach(p=>(p.fotos||[]).forEach((foto)=>{
      all.push({data:new Date(now-60*86400000),dataStr:"Sítio",foto,tipo:"Sítio",sub:p.texto});
    }));
    if(all.length===0) return null;
    // pega item aleatório, preferindo mais antigos
    const sorted=all.sort((a,b)=>a.data-b.data);
    const pick = sorted[Math.floor(Math.random()*sorted.length)];
    const dias=Math.floor((now-pick.data)/86400000);
    let recencia;
    if(dias<=7) recencia="Esta semana";
    else if(dias<=30) recencia="Há 30 dias";
    else if(dias<=90) recencia="Há 3 meses";
    else if(dias<=180) recencia="Há 6 meses";
    else if(dias<=365) recencia="Há 1 ano";
    else recencia=`Há ${Math.floor(dias/365)} anos`;
    return {...pick,recencia};
  },[pets,looks,makes,skDiario,sitioProjetos]);

  // Evolução da fazenda — métricas leves
  const evolucao = useMemo(()=>{
    const items=[];
    // Retinol em uso
    const retinol = skProdutos.find(p=>!p.fim && /retinol/i.test(p.nome));
    if(retinol && retinol.inicio){
      const d=daysSince(retinol.inicio);
      items.push({emoji:"🧴",titulo:"Retinol",valor:`${d} dias`,sub:"de acompanhamento",cor:T.rose,bg:T.roseBg});
    }
    if(skDiario.length>0){
      items.push({emoji:"📸",titulo:"Fotos da pele",valor:`${skDiario.length}`,sub:"registros",cor:T.rose,bg:T.roseBg});
    }
    // Pets em dia
    const totalVacinas = pets.reduce((s,p)=>s+p.vacinas.length,0);
    if(totalVacinas>0){
      const emDia = pets.reduce((s,p)=>s + p.vacinas.filter(v=>{
        const d=daysUntil(v.proxima); return d===null || d>7;
      }).length,0);
      items.push({emoji:"🐾",titulo:"Pets",valor:`${emDia}/${totalVacinas}`,sub:"vacinas em dia",cor:T.blue,bg:T.blueBg});
    }
    // Sítio concluídos este mês
    const sitioConcl = sitioProjetos.filter(p=>p.feita).length;
    if(sitioConcl>0){
      items.push({emoji:"🌳",titulo:"Sítio",valor:`${sitioConcl}`,sub:"tarefas concluídas",cor:T.moss,bg:T.mossBg});
    }
    // Closet looks
    if(looks.length>0){
      items.push({emoji:"👗",titulo:"Closet",valor:`${looks.length}`,sub:"looks registrados",cor:T.sand,bg:T.sandBg});
    }
    if(makes.length>0){
      items.push({emoji:"💄",titulo:"Beauty",valor:`${makes.length}`,sub:"makes no diário",cor:T.rose,bg:T.roseBg});
    }
    return items;
  },[pets,looks,makes,skDiario,skProdutos,sitioProjetos]);

  return(
    <div style={{display:"flex",flexDirection:"column",height:"100%"}}>
      <AppHeader title="ZenCow" showLogo onMenu={onMenu}/>
      <div style={{flex:1,overflowY:"auto",padding:"14px 16px 100px"}}>

        {/* ─────────── 1. CARD FLORA — Saudação principal ─────────── */}
        <Card style={{padding:"18px 16px",marginBottom:14,
          background:`linear-gradient(135deg, ${T.terraBg} 0%, ${T.bgCard} 100%)`,
          border:`1px solid ${T.terra}22`}}>
          <div style={{display:"flex",alignItems:"center",gap:14}}>
            <img src={m.img} alt="Flora" className="float-y" style={{width:84,height:84,objectFit:"contain",
              filter:"drop-shadow(0 4px 12px rgba(0,0,0,.15))",flexShrink:0}}/>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontSize:11,color:T.textMute,fontWeight:600,textTransform:"capitalize",letterSpacing:.3}}>
                {now.toLocaleDateString("pt-BR",{weekday:"long",day:"numeric",month:"long"})}
              </div>
              <div className="serif" style={{fontSize:24,fontWeight:700,color:T.text,marginTop:2,letterSpacing:-.5,lineHeight:1.1}}>
                {cumprimento}{nomeUsuario?`, ${nomeUsuario}`:""}
              </div>
              <div style={{fontSize:12,color:T.terra,fontStyle:"italic",marginTop:6,lineHeight:1.4,fontWeight:600}}>
                "{falaFlora}"
              </div>
              <div style={{fontSize:10,color:T.textMute,marginTop:2}}>— Flora</div>
            </div>
          </div>
        </Card>

        {/* ─────────── 2. MARGARIDA LEMBRA — Alertas dos pets ─────────── */}
        {alertasPets.length>0 ? (
          <Card style={{padding:"14px 14px",marginBottom:14,
            background:alertasPets[0].nivel==="danger"?T.dangerBg:T.alertBg,
            border:`1px solid ${alertasPets[0].nivel==="danger"?T.danger:T.alert}33`}}>
            <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:10}}>
              <img src={COW_MARGARIDA} alt="" style={{width:38,height:38,objectFit:"contain",flexShrink:0}}/>
              <div style={{flex:1}}>
                <div className="serif" style={{fontSize:17,fontWeight:700,color:T.text}}>Margarida lembra</div>
                <div style={{fontSize:11,color:T.textMute,fontStyle:"italic",marginTop:1}}>"Os bichinhos precisam de atenção"</div>
              </div>
            </div>
            {alertasPets.map((a,i)=>{
              const cor = a.nivel==="danger"?T.danger:T.alert;
              return (
                <button key={i} onClick={()=>onNavPet(a.petId)} style={{
                  display:"flex",alignItems:"center",gap:10,width:"100%",
                  padding:"8px 0",borderTop:`1px solid ${cor}22`,textAlign:"left"}}>
                  {a.foto?
                    <img src={a.foto} alt="" style={{width:32,height:32,borderRadius:"50%",objectFit:"cover",flexShrink:0,border:`2px solid ${cor}33`}}/>
                    :<div style={{width:32,height:32,borderRadius:"50%",background:cor+"22",
                      display:"flex",alignItems:"center",justifyContent:"center",fontSize:15,flexShrink:0}}>🐕</div>}
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:13,fontWeight:700,color:T.text}}>{a.pet}</div>
                    <div style={{fontSize:11,color:T.textMute,marginTop:1}}>{a.tipo}: {a.nome}</div>
                  </div>
                  <Pill label={formatDays(a.dias)} color={cor} bg="#fff"/>
                </button>
              );
            })}
          </Card>
        ) : pets.length>0 && (
          <Card style={{padding:"12px 14px",marginBottom:14,background:T.mossBg,border:`1px solid ${T.moss}22`}}>
            <div style={{display:"flex",alignItems:"center",gap:10}}>
              <img src={COW_MARGARIDA} alt="" style={{width:36,height:36,objectFit:"contain"}}/>
              <div style={{flex:1}}>
                <div style={{fontSize:13,fontWeight:700,color:T.text}}>Pets em dia ✓</div>
                <div style={{fontSize:11,color:T.textMute,fontStyle:"italic"}}>"Tudo certo com os bichinhos hoje"</div>
              </div>
              <button onClick={()=>onNav("pets")} style={{fontSize:11,color:T.moss,fontWeight:700}}>ver →</button>
            </div>
          </Card>
        )}

        {/* ─────────── 3. CAMÉLIA RECOMENDA — Autocuidado ─────────── */}
        <Card style={{padding:"14px 14px",marginBottom:14,
          background:T.roseBg,border:`1px solid ${T.rose}33`}}>
          <div style={{display:"flex",alignItems:"center",gap:12}}>
            <img src={COW_CAMELIA} alt="" className="float-y" style={{width:60,height:60,objectFit:"contain",flexShrink:0,
              filter:"drop-shadow(0 3px 8px rgba(0,0,0,.12))"}}/>
            <div style={{flex:1,minWidth:0}}>
              <div className="serif" style={{fontSize:16,fontWeight:700,color:T.rose,marginBottom:3}}>Camélia recomenda {camRecomenda.emoji}</div>
              <div style={{fontSize:13,color:T.text,lineHeight:1.4,marginBottom:8}}>{camRecomenda.texto}</div>
              <button onClick={()=>onNav("beauty")} style={{
                padding:"6px 14px",borderRadius:99,
                background:T.rose,color:"#fff",fontSize:12,fontWeight:700,
                boxShadow:"0 2px 8px rgba(176,122,122,.3)"}}>{camRecomenda.cta}</button>
            </div>
          </div>
        </Card>

        {/* ─────────── 4. MEMÓRIA DO DIA ⭐ ─────────── */}
        {memoriaDoDia && (
          <Card style={{padding:"14px 14px",marginBottom:14,
            background:`linear-gradient(135deg, ${T.lavBg} 0%, ${T.bgCard} 100%)`,
            border:`1px solid ${T.lav}33`}}>
            <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12}}>
              <img src={COW_MIMOSA} alt="" style={{width:38,height:38,objectFit:"contain",flexShrink:0}}/>
              <div style={{flex:1}}>
                <div className="serif" style={{fontSize:17,fontWeight:700,color:T.lav}}>Memória do dia</div>
                <div style={{fontSize:11,color:T.textMute,fontStyle:"italic",marginTop:1}}>"Olha essa lembrança..."</div>
              </div>
              <Pill label={memoriaDoDia.recencia} color={T.lav} bg="#fff"/>
            </div>
            <button onClick={()=>onNav("memorias")} style={{
              display:"block",width:"100%",borderRadius:14,overflow:"hidden",
              border:`2px solid ${T.lav}44`,background:T.bgCard,padding:0}}>
              <div style={{aspectRatio:"4/3",overflow:"hidden",background:T.bgInput,
                display:"flex",alignItems:"center",justifyContent:"center"}}>
                <img src={memoriaDoDia.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover",display:"block"}}/>
              </div>
              <div style={{padding:"10px 14px",textAlign:"left",background:T.bgCard}}>
                <div style={{fontSize:12,color:T.lav,fontWeight:800,letterSpacing:.3}}>{memoriaDoDia.tipo.toUpperCase()}</div>
                <div style={{fontSize:13,fontWeight:700,color:T.text,marginTop:2,
                  overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{memoriaDoDia.sub}</div>
                <div style={{fontSize:11,color:T.textMute,marginTop:1}}>{memoriaDoDia.dataStr}</div>
              </div>
            </button>
          </Card>
        )}

        {/* ─────────── 5. EVOLUÇÃO DA FAZENDA ─────────── */}
        {evolucao.length>0 && (
          <Card style={{padding:"14px 14px",marginBottom:14}}>
            <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:12}}>
              <img src={COW_ESTRELA} alt="" style={{width:36,height:36,objectFit:"contain",flexShrink:0}}/>
              <div style={{flex:1}}>
                <div className="serif" style={{fontSize:16,fontWeight:700,color:T.moss}}>Evolução da fazenda</div>
                <div style={{fontSize:11,color:T.textMute,fontStyle:"italic"}}>"Pequenos passos, grandes colheitas"</div>
              </div>
            </div>
            <div style={{display:"flex",gap:8,overflowX:"auto",paddingBottom:4}}>
              {evolucao.map((it,i)=>(
                <div key={i} style={{flexShrink:0,minWidth:120,padding:"11px 12px",
                  borderRadius:12,background:it.bg,border:`1px solid ${it.cor}22`}}>
                  <div style={{fontSize:18,marginBottom:4}}>{it.emoji}</div>
                  <div style={{fontSize:10,fontWeight:700,color:T.textMute,letterSpacing:.3,textTransform:"uppercase"}}>{it.titulo}</div>
                  <div className="serif" style={{fontSize:18,fontWeight:700,color:it.cor,marginTop:2,letterSpacing:-.3}}>{it.valor}</div>
                  <div style={{fontSize:10,color:T.textSub,marginTop:1}}>{it.sub}</div>
                </div>
              ))}
            </div>
          </Card>
        )}

        {/* ─────────── 6. ATALHOS RÁPIDOS ─────────── */}
        <Card style={{padding:"14px 14px"}}>
          <div className="serif" style={{fontWeight:700,fontSize:16,marginBottom:12,color:T.text}}>Atalhos rápidos</div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8}}>
            {[
              {id:"closet",label:"Novo look",cor:T.sand,bg:T.sandBg,emoji:"👗"},
              {id:"beauty",label:"Nova make",cor:T.rose,bg:T.roseBg,emoji:"💄"},
              {id:"beauty",label:"Foto pele",cor:T.rose,bg:T.roseBg,emoji:"📸"},
              {id:"pets",label:"Pets",cor:T.blue,bg:T.blueBg,emoji:"🐾"},
              {id:"casa",label:"Casa & Sítio",cor:T.moss,bg:T.mossBg,emoji:"🏡"},
              {id:"memorias",label:"Memórias",cor:T.lav,bg:T.lavBg,emoji:"💫"},
            ].map((a,i)=>(
              <button key={i} onClick={()=>onNav(a.id)} style={{
                padding:"14px 6px",borderRadius:14,
                background:a.bg,border:`1px solid ${a.cor}22`,
                display:"flex",flexDirection:"column",alignItems:"center",gap:6,
                transition:"transform .12s"}}
                onMouseDown={e=>e.currentTarget.style.transform="scale(0.96)"}
                onMouseUp={e=>e.currentTarget.style.transform="scale(1)"}
                onMouseLeave={e=>e.currentTarget.style.transform="scale(1)"}>
                <span style={{fontSize:26}}>{a.emoji}</span>
                <span style={{fontSize:11,fontWeight:700,color:a.cor}}>{a.label}</span>
              </button>
            ))}
          </div>
        </Card>

      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════════════════
   TELA AGENDA — Calendário completo (mensal, próximos eventos, categorias)
═══════════════════════════════════════════════════════════════════════════ */
function TelaAgenda({agenda,setAgenda,onMenu}){
  const [view,setView]=useState("mes"); // mes | proximos
  const [mesSel,setMesSel]=useState(now.getMonth());
  const [anoSel,setAnoSel]=useState(now.getFullYear());
  const [diaSel,setDiaSel]=useState(now.getDate());
  const [filtro,setFiltro]=useState("Todas");
  const [addModal,setAddModal]=useState(false);
  const [editEv,setEditEv]=useState(null);

  const categorias=[
    {l:"Todas",cor:T.text,bg:T.bgInput},
    {l:"Estudos",cor:T.terra,bg:T.terraBg},
    {l:"Pets",cor:T.blue,bg:T.blueBg},
    {l:"Beauty",cor:T.rose,bg:T.roseBg},
    {l:"Skincare",cor:T.rose,bg:T.roseBg},
    {l:"Casa",cor:T.moss,bg:T.mossBg},
    {l:"Looks",cor:T.sand,bg:T.sandBg},
    {l:"Pessoal",cor:T.lav,bg:T.lavBg},
  ];
  const corPorCategoria = (cat)=>{
    const c = categorias.find(x=>x.l===cat);
    return c ? {cor:c.cor,bg:c.bg} : {cor:T.terra,bg:T.terraBg};
  };

  // grade do mês
  const primeiroDiaSemana=new Date(anoSel,mesSel,1).getDay();
  const diasNoMes=new Date(anoSel,mesSel+1,0).getDate();
  const cells=Array.from({length:primeiroDiaSemana+diasNoMes},(_,i)=>i<primeiroDiaSemana?null:i-primeiroDiaSemana+1);
  const baseDate=new Date(now.getFullYear(),now.getMonth(),now.getDate());

  const eventosDia = useMemo(()=>{
    const selDate=new Date(anoSel,mesSel,diaSel);
    const diff=Math.round((selDate-baseDate)/86400000);
    let evs=agenda.filter(e=>e.dia===diff);
    if(filtro!=="Todas") evs=evs.filter(e=>e.categoria===filtro);
    return evs.sort((a,b)=>a.hora.localeCompare(b.hora));
  },[agenda,mesSel,anoSel,diaSel,filtro,baseDate]);

  // próximos 14 dias
  const proximos = useMemo(()=>{
    let p=agenda.filter(e=>e.dia>=0 && e.dia<=14);
    if(filtro!=="Todas") p=p.filter(e=>e.categoria===filtro);
    return p.sort((a,b)=>a.dia-b.dia || a.hora.localeCompare(b.hora));
  },[agenda,filtro]);

  const prevMes=()=>{if(mesSel===0){setMesSel(11);setAnoSel(a=>a-1);}else setMesSel(m=>m-1);};
  const nextMes=()=>{if(mesSel===11){setMesSel(0);setAnoSel(a=>a+1);}else setMesSel(m=>m+1);};

  const salvar=(form)=>{
    if(editEv){
      setAgenda(ag=>ag.map(e=>e.id===editEv.id?{...e,...form}:e));
    } else {
      const selDate=new Date(anoSel,mesSel,diaSel);
      const diff=Math.round((selDate-baseDate)/86400000);
      setAgenda(ag=>[...ag,{id:Date.now(),...form,dia:diff}]);
    }
    setEditEv(null);
    setAddModal(false);
  };
  const deletar=id=>setAgenda(ag=>ag.filter(e=>e.id!==id));

  const formatDiaPrazo=(dia)=>{
    if(dia===0) return "Hoje";
    if(dia===1) return "Amanhã";
    if(dia<7) return `Em ${dia} dias`;
    if(dia<14) return `Em ${Math.floor(dia/7)} sem`;
    return `Em ${dia}d`;
  };

  return (
    <div style={{display:"flex",flexDirection:"column",height:"100%"}}>
      <AppHeader title="Agenda" onMenu={onMenu}/>
      <div style={{flex:1,overflowY:"auto",padding:"14px 16px 100px"}}>

        <MascoteHeader secao="hoje" sub="Calendário e compromissos"/>

        {/* Toggle visualização */}
        <div style={{display:"flex",background:T.bgInput,borderRadius:11,padding:3,gap:3,marginBottom:14}}>
          {[{id:"mes",l:"📅 Mês"},{id:"proximos",l:"⏰ Próximos"}].map(t=>(
            <button key={t.id} onClick={()=>setView(t.id)} style={{
              flex:1,padding:"8px 0",borderRadius:8,fontSize:13,fontWeight:700,
              background:view===t.id?T.bgCard:"transparent",
              border:view===t.id?`1px solid ${T.border}`:"none",
              color:view===t.id?T.text:T.textMute}}>{t.l}</button>
          ))}
        </div>

        {/* Filtro de categorias */}
        <div style={{display:"flex",gap:6,overflowX:"auto",marginBottom:14,paddingBottom:4}}>
          {categorias.map(c=>(
            <button key={c.l} onClick={()=>setFiltro(c.l)} style={{
              padding:"5px 12px",borderRadius:99,fontSize:11,fontWeight:700,
              background:filtro===c.l?c.cor:T.bgCard,color:filtro===c.l?"#fff":T.textSub,
              border:`1px solid ${filtro===c.l?c.cor:T.border}`,
              whiteSpace:"nowrap",flexShrink:0}}>{c.l}</button>
          ))}
        </div>

        {view==="mes" && <>
          {/* Navegação mensal */}
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
            <button onClick={prevMes} style={{width:34,height:34,borderRadius:10,
              background:T.bgCard,border:`1px solid ${T.border}`,fontSize:18,
              display:"flex",alignItems:"center",justifyContent:"center",color:T.textSub}}>‹</button>
            <span className="serif" style={{fontWeight:700,fontSize:18,letterSpacing:-.3}}>{MESES_FULL[mesSel]} {anoSel}</span>
            <button onClick={nextMes} style={{width:34,height:34,borderRadius:10,
              background:T.bgCard,border:`1px solid ${T.border}`,fontSize:18,
              display:"flex",alignItems:"center",justifyContent:"center",color:T.textSub}}>›</button>
          </div>

          <Card style={{padding:"12px",marginBottom:14}}>
            <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:2,marginBottom:6}}>
              {WEEK_L.map((l,i)=>(
                <div key={i} style={{textAlign:"center",fontSize:10,color:T.textMute,fontWeight:700,padding:"3px 0"}}>{l}</div>
              ))}
            </div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:3}}>
              {cells.map((d,i)=>{
                if(!d) return <div key={i}/>;
                const cellDate=new Date(anoSel,mesSel,d);
                const diff=Math.round((cellDate-baseDate)/86400000);
                const evs=agenda.filter(e=>e.dia===diff && (filtro==="Todas"||e.categoria===filtro));
                const dots=[...new Set(evs.map(e=>e.cor))].slice(0,3);
                const isSel=d===diaSel;
                const isHoje=d===now.getDate()&&mesSel===now.getMonth()&&anoSel===now.getFullYear();
                return (
                  <button key={i} onClick={()=>setDiaSel(d)} style={{
                    aspectRatio:"1",borderRadius:10,fontSize:13,fontWeight:isSel?800:500,
                    background:isSel?T.terra:"transparent",
                    color:isSel?"#fff":isHoje?T.terra:T.text,
                    border:isHoje&&!isSel?`1.5px solid ${T.terra}`:"none",
                    position:"relative",display:"flex",flexDirection:"column",alignItems:"center",
                    justifyContent:"center",gap:2,transition:"all .12s"}}>
                    <span>{d}</span>
                    {dots.length>0 && (
                      <div style={{display:"flex",gap:2,height:4,alignItems:"center"}}>
                        {dots.map((cor,ci)=>(
                          <div key={ci} style={{width:4,height:4,borderRadius:"50%",
                            background:isSel?"rgba(255,255,255,.85)":cor}}/>
                        ))}
                      </div>
                    )}
                  </button>
                );
              })}
            </div>
          </Card>

          {/* Eventos do dia selecionado */}
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
            <span className="serif" style={{fontWeight:700,fontSize:16}}>
              {diaSel} de {MESES_FULL[mesSel]} ({eventosDia.length})
            </span>
            <button onClick={()=>{setEditEv(null);setAddModal(true);}} style={{
              padding:"6px 14px",borderRadius:99,fontSize:12,fontWeight:700,
              background:T.terra,color:"#fff",boxShadow:"0 2px 8px rgba(196,101,74,.3)"}}>+ Evento</button>
          </div>

          {eventosDia.length===0 ? (
            <Card style={{padding:"24px",textAlign:"center"}}>
              <div style={{fontSize:13,color:T.textMute,fontStyle:"italic"}}>Nenhum evento neste dia 🌿</div>
            </Card>
          ) : (
            <div style={{display:"flex",flexDirection:"column",gap:8}}>
              {eventosDia.map(ev=>(
                <Card key={ev.id} style={{padding:"12px 14px"}}>
                  <div style={{display:"flex",alignItems:"center",gap:12}}>
                    <div style={{width:5,height:42,borderRadius:99,background:ev.cor,flexShrink:0}}/>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{display:"flex",alignItems:"center",gap:8}}>
                        <span style={{fontSize:14,fontWeight:700,color:T.text}}>{ev.titulo}</span>
                        {ev.categoria && <Pill label={ev.categoria} color={ev.cor} bg={ev.bg}/>}
                      </div>
                      <div style={{fontSize:12,color:T.textMute,marginTop:2}}>
                        {ev.hora} · {ev.durMin}min{ev.recorrencia?` · ${ev.recorrencia}`:""}
                      </div>
                    </div>
                    <IconBtn icon="✏️" onClick={()=>{setEditEv(ev);setAddModal(true);}}/>
                    <IconBtn icon="🗑️" onClick={()=>deletar(ev.id)}/>
                  </div>
                </Card>
              ))}
            </div>
          )}
        </>}

        {view==="proximos" && <>
          {proximos.length===0 ? (
            <Card style={{padding:"30px 20px",textAlign:"center"}}>
              <div style={{fontSize:28,marginBottom:10}}>🌿</div>
              <div style={{fontSize:14,fontWeight:700,marginBottom:4}}>Nada à vista</div>
              <div style={{fontSize:12,color:T.textMute,fontStyle:"italic"}}>
                Você não tem compromissos próximos
              </div>
            </Card>
          ) : (
            <div style={{display:"flex",flexDirection:"column",gap:8}}>
              {(()=>{
                let lastDia=-99;
                return proximos.map(ev=>{
                  const showHeader = ev.dia!==lastDia;
                  lastDia=ev.dia;
                  return (
                    <div key={ev.id}>
                      {showHeader && (
                        <div style={{fontSize:11,color:T.textMute,fontWeight:700,
                          textTransform:"uppercase",letterSpacing:.6,marginTop:showHeader?6:0,marginBottom:6}}>
                          {formatDiaPrazo(ev.dia)}
                        </div>
                      )}
                      <Card style={{padding:"12px 14px",marginBottom:6}}>
                        <div style={{display:"flex",alignItems:"center",gap:12}}>
                          <div style={{width:5,height:42,borderRadius:99,background:ev.cor,flexShrink:0}}/>
                          <div style={{flex:1,minWidth:0}}>
                            <div style={{display:"flex",alignItems:"center",gap:8}}>
                              <span style={{fontSize:14,fontWeight:700}}>{ev.titulo}</span>
                              {ev.categoria && <Pill label={ev.categoria} color={ev.cor} bg={ev.bg}/>}
                            </div>
                            <div style={{fontSize:12,color:T.textMute,marginTop:2}}>{ev.hora} · {ev.durMin}min</div>
                          </div>
                          <IconBtn icon="✏️" onClick={()=>{setEditEv(ev);setAddModal(true);}}/>
                          <IconBtn icon="🗑️" onClick={()=>deletar(ev.id)}/>
                        </div>
                      </Card>
                    </div>
                  );
                });
              })()}
            </div>
          )}

          <button onClick={()=>{setEditEv(null);setAddModal(true);}} style={{
            width:"100%",padding:"13px",borderRadius:12,marginTop:14,
            background:T.terra,color:"#fff",fontSize:14,fontWeight:700,
            boxShadow:"0 2px 12px rgba(196,101,74,.3)"}}>+ Novo Evento</button>
        </>}
      </div>

      {addModal && <EventoModal evento={editEv} categorias={categorias.slice(1)} corPorCategoria={corPorCategoria}
        onClose={()=>{setAddModal(false);setEditEv(null);}}
        onSave={salvar}/>}
    </div>
  );
}

function EventoModal({evento,categorias,corPorCategoria,onClose,onSave}){
  const [form,setForm]=useState(evento||{titulo:"",hora:"09:00",durMin:60,categoria:"Pessoal",recorrencia:"",cor:T.lav,bg:T.lavBg});

  const setCat=(cat)=>{
    const {cor,bg}=corPorCategoria(cat);
    setForm(f=>({...f,categoria:cat,cor,bg}));
  };

  return (
    <Modal title={evento?"Editar Evento":"Novo Evento"} onClose={onClose}>
      <div style={{display:"flex",flexDirection:"column",gap:12}}>
        <Input label="Título" value={form.titulo} onChange={e=>setForm(f=>({...f,titulo:e.target.value}))} placeholder="Ex: Banho do Bento"/>
        <div style={{display:"flex",gap:10}}>
          <div style={{flex:1}}>
            <Input label="Horário" type="time" value={form.hora} onChange={e=>setForm(f=>({...f,hora:e.target.value}))}/>
          </div>
          <div style={{flex:1}}>
            <Input label="Duração (min)" type="number" value={form.durMin} onChange={e=>setForm(f=>({...f,durMin:Number(e.target.value)||30}))}/>
          </div>
        </div>
        <div>
          <div style={{fontSize:11,color:T.textMute,fontWeight:700,marginBottom:7,letterSpacing:.3}}>CATEGORIA</div>
          <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
            {categorias.map(c=>{
              const sel=form.categoria===c.l;
              return (
                <button key={c.l} onClick={()=>setCat(c.l)} style={{
                  padding:"5px 12px",borderRadius:99,fontSize:11,fontWeight:700,
                  background:sel?c.cor:c.bg,color:sel?"#fff":c.cor,
                  border:`1.5px solid ${sel?c.cor:T.border}`}}>{c.l}</button>
              );
            })}
          </div>
        </div>
        <Select label="Recorrência" value={form.recorrencia||""} onChange={e=>setForm(f=>({...f,recorrencia:e.target.value}))}
          options={[{v:"",l:"Sem recorrência"},{v:"Diária",l:"Diária"},{v:"Semanal",l:"Semanal"},{v:"Mensal",l:"Mensal"},{v:"A cada 30 dias",l:"A cada 30 dias"}]}/>
        <ModalActions onCancel={onClose} onSave={()=>onSave(form)} color={T.terra} saveLabel={evento?"Salvar":"Adicionar"}/>
      </div>
    </Modal>
  );
}

/* ════════════════════════════════════════════════════════════════════════════
   TELA PETS — Lista + Ficha individual
═══════════════════════════════════════════════════════════════════════════ */
function TelaPets({pets,setPets,petOpenId,setPetOpenId,onMenu}){
  if(petOpenId){
    const pet=pets.find(p=>p.id===petOpenId);
    if(pet) return <PetDetail pet={pet} setPets={setPets} onBack={()=>setPetOpenId(null)}/>;
  }
  return <PetsList pets={pets} setPets={setPets} onOpen={id=>setPetOpenId(id)} onMenu={onMenu}/>;
}

function PetsList({pets,setPets,onOpen,onMenu}){
  const [addModal,setAddModal]=useState(false);
  const [form,setForm]=useState({nome:"",raca:"",sexo:"M",obs:"",foto:null});
  const fileRefAdd=useRef();

  const adicionar=()=>{
    if(!form.nome.trim())return;
    setPets(ps=>[...ps,{id:Date.now(),nome:form.nome.trim(),raca:form.raca.trim(),
      sexo:form.sexo,nascimento:"",foto:form.foto,peso:"",obs:form.obs.trim(),
      vacinas:[],vermifugos:[],antipulgas:[],consultas:[],exames:[],
      medicamentos:[],banhos:[],gastos:[],galeria:[]}]);
    setForm({nome:"",raca:"",sexo:"M",obs:"",foto:null});
    setAddModal(false);
  };
  const handleFotoAdd=async e=>{
    const f=e.target.files[0]; if(!f) return;
    const data=await compressImage(f,800,0.85);
    setForm(x=>({...x,foto:data}));
  };

  const m = MASCOTES.pets;

  return(
    <div style={{display:"flex",flexDirection:"column",height:"100%"}}>
      <AppHeader title="Pets" onMenu={onMenu}/>
      <div style={{flex:1,overflowY:"auto",padding:"14px 16px 100px"}}>
        <MascoteHeader secao="pets" sub={`${pets.length} cachorros na família`}/>

        {(()=>{
          const all=getAllPetAlerts(pets);
          if(all.length===0) return null;
          const danger=all.filter(a=>a.nivel==="danger").length;
          const alert=all.filter(a=>a.nivel==="alert").length;
          return (
            <Card style={{padding:"12px 14px",marginBottom:14,
              background:T.alertBg,border:`1px solid ${T.alert}33`}}>
              <div style={{fontSize:12,fontWeight:700,color:T.text,marginBottom:6}}>📌 Resumo geral</div>
              <div style={{display:"flex",gap:8}}>
                {danger>0&&<Pill label={`${danger} atrasado${danger>1?"s":""}`} color={T.danger} bg="#fff"/>}
                {alert>0&&<Pill label={`${alert} próximo${alert>1?"s":""}`} color={T.alert} bg="#fff"/>}
              </div>
            </Card>
          );
        })()}

        <div style={{display:"flex",flexDirection:"column",gap:10,marginBottom:14}}>
          {pets.map((p,idx)=>{
            const alertas=getPetAlerts(p);
            const urgentes=alertas.filter(a=>a.nivel==="danger").length;
            const proximos=alertas.filter(a=>a.nivel==="alert").length;
            return(
              <button key={p.id} onClick={()=>onOpen(p.id)} style={{
                display:"flex",alignItems:"center",gap:14,
                padding:"14px 16px",borderRadius:18,
                background:T.bgCard,border:`1px solid ${T.border}`,
                textAlign:"left"}}>
                <div style={{width:62,height:62,borderRadius:20,background:T.blueBg,
                  display:"flex",alignItems:"center",justifyContent:"center",
                  fontSize:30,flexShrink:0,overflow:"hidden",
                  border:`1.5px solid ${T.blue}33`}}>
                  {p.foto?
                    <img src={p.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
                    :<span>🐕</span>}
                </div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{display:"flex",alignItems:"baseline",gap:6}}>
                    <span className="serif" style={{fontSize:18,fontWeight:700,color:T.text}}>{p.nome}</span>
                    <span style={{fontSize:10,color:T.textMute,fontWeight:700}}>#{idx+1}</span>
                  </div>
                  <div style={{fontSize:12,color:T.textSub,marginTop:1}}>
                    {p.raca}{p.sexo?` · ${p.sexo==="M"?"♂":"♀"}`:""}
                  </div>
                  <div style={{display:"flex",gap:6,marginTop:6}}>
                    {urgentes>0&&<Pill label={`⚠️ ${urgentes}`} color={T.danger} bg={T.dangerBg}/>}
                    {proximos>0&&<Pill label={`🟡 ${proximos}`} color={T.alert} bg={T.alertBg}/>}
                    {urgentes===0&&proximos===0&&<Pill label="em dia" color={T.moss} bg={T.mossBg}/>}
                  </div>
                </div>
                <svg width="8" height="14" viewBox="0 0 8 14" fill="none">
                  <path d="M1 1L7 7L1 13" stroke={T.textMute} strokeWidth="1.8" strokeLinecap="round"/>
                </svg>
              </button>
            );
          })}
        </div>

        <button onClick={()=>setAddModal(true)} style={{
          width:"100%",padding:"13px",borderRadius:12,
          background:T.blue,color:"#fff",fontSize:14,fontWeight:700,
          boxShadow:"0 2px 12px rgba(106,143,170,.3)"}}>+ Adicionar Pet</button>
      </div>

      {addModal&&(
        <Modal title="Novo Pet" onClose={()=>setAddModal(false)}>
          <div style={{display:"flex",flexDirection:"column",gap:14}}>
            <div style={{display:"flex",alignItems:"center",gap:14}}>
              <button onClick={()=>fileRefAdd.current.click()} style={{
                width:62,height:62,borderRadius:18,background:T.blueBg,
                display:"flex",alignItems:"center",justifyContent:"center",
                flexShrink:0,overflow:"hidden",
                border:`2px dashed ${form.foto?T.blue:T.borderMd}`}}>
                {form.foto?
                  <img src={form.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
                  : <span style={{fontSize:24}}>📷</span>}
              </button>
              <input ref={fileRefAdd} type="file" accept="image/*" style={{display:"none"}} onChange={handleFotoAdd}/>
              <div style={{fontSize:12,color:T.textMute}}>Toque para foto</div>
            </div>
            <Input label="Nome" value={form.nome} onChange={e=>setForm(f=>({...f,nome:e.target.value}))}/>
            <Input label="Raça" value={form.raca} onChange={e=>setForm(f=>({...f,raca:e.target.value}))}/>
            <Select label="Sexo" value={form.sexo} onChange={e=>setForm(f=>({...f,sexo:e.target.value}))}
              options={[{v:"M",l:"Macho"},{v:"F",l:"Fêmea"}]}/>
            <ModalActions onCancel={()=>setAddModal(false)} onSave={adicionar} saveLabel="Adicionar" color={T.blue}/>
          </div>
        </Modal>
      )}
    </div>
  );
}

/* === DETALHE DO PET === */
function PetDetail({pet,setPets,onBack}){
  const [tab,setTab]=useState("saude");
  const [editInfo,setEditInfo]=useState(false);
  const fotoRef=useRef();
  const update=(patch)=>setPets(ps=>ps.map(p=>p.id===pet.id?{...p,...patch}:p));
  const handleFoto=async e=>{
    const f=e.target.files[0]; if(!f) return;
    const data=await compressImage(f,800,0.85);
    update({foto:data});
  };
  const deletePet=()=>{
    if(window.confirm(`Remover ${pet.nome}? Esta ação é permanente.`)){
      setPets(ps=>ps.filter(p=>p.id!==pet.id));
      onBack();
    }
  };
  const alertas=getPetAlerts(pet);

  return(
    <div style={{display:"flex",flexDirection:"column",height:"100%"}}>
      <AppHeader title={pet.nome} onBack={onBack}
        rightAction={
          <button onClick={deletePet} style={{width:34,height:34,borderRadius:10,
            background:T.bgCard,border:`1px solid ${T.border}`,
            display:"flex",alignItems:"center",justifyContent:"center",fontSize:14}}>🗑️</button>
        }/>
      <div style={{flex:1,overflowY:"auto",padding:"14px 16px 100px"}}>

        <Card style={{padding:"18px 16px",marginBottom:14}}>
          <div style={{display:"flex",alignItems:"center",gap:14,marginBottom:14}}>
            <button onClick={()=>fotoRef.current.click()} style={{
              width:84,height:84,borderRadius:24,background:T.blueBg,
              display:"flex",alignItems:"center",justifyContent:"center",
              flexShrink:0,overflow:"hidden",position:"relative",
              border:`2px solid ${T.blue}33`}}>
              {pet.foto?
                <img src={pet.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
                : <span style={{fontSize:38}}>🐕</span>}
              <div style={{position:"absolute",bottom:3,right:3,width:22,height:22,
                borderRadius:"50%",background:T.blue,
                display:"flex",alignItems:"center",justifyContent:"center",
                fontSize:11,color:"#fff",border:`2px solid ${T.bgCard}`}}>📷</div>
            </button>
            <input ref={fotoRef} type="file" accept="image/*" style={{display:"none"}} onChange={handleFoto}/>
            <div style={{flex:1,minWidth:0}}>
              <div className="serif" style={{fontSize:22,fontWeight:700,color:T.text,letterSpacing:-.3}}>{pet.nome}</div>
              <div style={{fontSize:13,color:T.textSub,marginTop:2}}>
                {pet.raca} · {pet.sexo==="M"?"Macho":"Fêmea"}
              </div>
              {pet.peso && <div style={{fontSize:12,color:T.textMute,marginTop:1}}>{pet.peso}</div>}
              <button onClick={()=>setEditInfo(true)} style={{
                fontSize:11,fontWeight:700,color:T.blue,marginTop:8,
                padding:"3px 10px",borderRadius:99,
                background:T.blueBg,border:`1px solid ${T.blue}33`}}>
                ✏️ Editar
              </button>
            </div>
          </div>
          {pet.obs && (
            <div style={{padding:"10px 12px",background:T.bgInput,borderRadius:10,
              fontSize:12,color:T.textSub,fontStyle:"italic"}}>
              "{pet.obs}"
            </div>
          )}
        </Card>

        {alertas.length>0 && (
          <Card style={{padding:"12px 14px",marginBottom:14,
            background:alertas[0].nivel==="danger"?T.dangerBg:T.alertBg,
            border:`1px solid ${alertas[0].nivel==="danger"?T.danger:T.alert}33`}}>
            <div style={{fontSize:12,fontWeight:800,color:T.text,marginBottom:8,display:"flex",alignItems:"center",gap:6}}>
              <img src={COW_MARGARIDA} alt="" style={{width:24,height:24,objectFit:"contain"}}/>
              Atenção
            </div>
            {alertas.map((a,i)=>{
              const cor=a.nivel==="danger"?T.danger:T.alert;
              return(
                <div key={i} style={{display:"flex",alignItems:"center",gap:8,
                  padding:"5px 0",borderTop:i>0?`1px solid ${cor}22`:"none"}}>
                  <span style={{fontSize:12,fontWeight:700,color:T.text,flex:1}}>{a.tipo}: {a.nome}</span>
                  <Pill label={formatDays(a.dias)} color={cor} bg="#fff"/>
                </div>
              );
            })}
          </Card>
        )}

        <div style={{display:"flex",background:T.bgInput,borderRadius:11,padding:3,gap:3,marginBottom:14,overflowX:"auto"}}>
          {[
            {id:"saude",l:"🏥 Saúde"},
            {id:"rotina",l:"🛁 Rotina"},
            {id:"galeria",l:"📸 Galeria"},
            {id:"gastos",l:"💰 Gastos"},
            {id:"historico",l:"📅 Histórico"},
          ].map(t=>(
            <button key={t.id} onClick={()=>setTab(t.id)} style={{
              flex:"1 0 auto",padding:"7px 12px",borderRadius:8,fontSize:11,fontWeight:700,
              background:tab===t.id?T.bgCard:"transparent",
              border:tab===t.id?`1px solid ${T.border}`:"none",
              color:tab===t.id?T.text:T.textMute,whiteSpace:"nowrap"}}>{t.l}</button>
          ))}
        </div>

        {tab==="saude" && <PetSaude pet={pet} update={update}/>}
        {tab==="rotina" && <PetRotina pet={pet} update={update}/>}
        {tab==="galeria" && <PetGaleria pet={pet} update={update}/>}
        {tab==="gastos" && <PetGastos pet={pet} update={update}/>}
        {tab==="historico" && <PetHistorico pet={pet}/>}
      </div>

      {editInfo && (
        <PetEditInfo pet={pet} onSave={(patch)=>{update(patch);setEditInfo(false);}} onClose={()=>setEditInfo(false)}/>
      )}
    </div>
  );
}

function PetEditInfo({pet,onSave,onClose}){
  const [form,setForm]=useState({
    nome:pet.nome,raca:pet.raca,sexo:pet.sexo,
    peso:pet.peso||"",obs:pet.obs||"",nascimento:pet.nascimento||"",
  });
  return (
    <Modal title="Editar Informações" onClose={onClose}>
      <div style={{display:"flex",flexDirection:"column",gap:12}}>
        <Input label="Nome" value={form.nome} onChange={e=>setForm(f=>({...f,nome:e.target.value}))}/>
        <Input label="Raça" value={form.raca} onChange={e=>setForm(f=>({...f,raca:e.target.value}))}/>
        <Select label="Sexo" value={form.sexo} onChange={e=>setForm(f=>({...f,sexo:e.target.value}))}
          options={[{v:"M",l:"Macho"},{v:"F",l:"Fêmea"}]}/>
        <Input label="Peso" value={form.peso} onChange={e=>setForm(f=>({...f,peso:e.target.value}))} placeholder="Ex: 28 kg"/>
        <Input label="Nascimento" value={form.nascimento} onChange={e=>setForm(f=>({...f,nascimento:e.target.value}))} placeholder="dd/mm/aaaa"/>
        <div>
          <div style={{fontSize:11,color:T.textMute,fontWeight:700,marginBottom:5,letterSpacing:.3}}>OBSERVAÇÕES</div>
          <textarea value={form.obs} onChange={e=>setForm(f=>({...f,obs:e.target.value}))} rows={3}
            style={{width:"100%",padding:"10px 13px",borderRadius:10,
              border:`1px solid ${T.border}`,background:T.bgInput,fontSize:13,color:T.text,resize:"none"}}/>
        </div>
        <ModalActions onCancel={onClose} onSave={()=>onSave(form)} color={T.blue}/>
      </div>
    </Modal>
  );
}

function PetSaude({pet,update}){
  const [editType,setEditType]=useState(null);
  const [editItem,setEditItem]=useState(null);
  const openAdd=type=>{setEditItem(null);setEditType(type);};
  const openEdit=(type,item)=>{setEditItem(item);setEditType(type);};

  return(
    <>
      <SaudeSection title="💉 Vacinas" items={pet.vacinas}
        onAdd={()=>openAdd("vacina")}
        onEdit={i=>openEdit("vacina",i)}
        onDelete={id=>update({vacinas:pet.vacinas.filter(v=>v.id!==id)})}
        render={v=>({primary:v.nome,secondary:`Aplicada: ${v.data}`,next:`Próxima: ${v.proxima}`})}/>
      <SaudeSection title="🪱 Vermífugo" items={pet.vermifugos}
        onAdd={()=>openAdd("vermifugo")}
        onEdit={i=>openEdit("vermifugo",i)}
        onDelete={id=>update({vermifugos:pet.vermifugos.filter(v=>v.id!==id)})}
        render={v=>({primary:v.produto,secondary:`Aplicado: ${v.data}`,next:`Próximo: ${v.proxima}`})}/>
      <SaudeSection title="🐛 Antipulgas" items={pet.antipulgas}
        onAdd={()=>openAdd("antipulga")}
        onEdit={i=>openEdit("antipulga",i)}
        onDelete={id=>update({antipulgas:pet.antipulgas.filter(v=>v.id!==id)})}
        render={v=>({primary:v.produto,secondary:`Aplicado: ${v.data}`,next:`Próximo: ${v.proxima}`})}/>
      <SaudeSection title="🩺 Consultas" items={pet.consultas}
        onAdd={()=>openAdd("consulta")}
        onEdit={i=>openEdit("consulta",i)}
        onDelete={id=>update({consultas:pet.consultas.filter(v=>v.id!==id)})}
        render={v=>({primary:v.motivo||"Consulta",secondary:`${v.data} · ${v.vet||"—"}`,next:v.observacoes})}/>
      <SaudeSection title="🔬 Exames" items={pet.exames}
        onAdd={()=>openAdd("exame")}
        onEdit={i=>openEdit("exame",i)}
        onDelete={id=>update({exames:pet.exames.filter(v=>v.id!==id)})}
        render={v=>({primary:v.tipo,secondary:v.data,next:v.resultado})}/>
      <SaudeSection title="✂️ Cirurgias" items={pet.cirurgias||[]}
        onAdd={()=>openAdd("cirurgia")}
        onEdit={i=>openEdit("cirurgia",i)}
        onDelete={id=>update({cirurgias:(pet.cirurgias||[]).filter(v=>v.id!==id)})}
        render={v=>({primary:v.tipo,secondary:v.data,next:v.observacoes})}/>
      <SaudeSection title="💊 Medicamentos" items={pet.medicamentos}
        onAdd={()=>openAdd("medicamento")}
        onEdit={i=>openEdit("medicamento",i)}
        onDelete={id=>update({medicamentos:pet.medicamentos.filter(v=>v.id!==id)})}
        render={v=>({primary:v.nome,secondary:v.dose,next:v.frequencia})}/>
      {editType && <SaudeEditModal type={editType} item={editItem} pet={pet} update={update}
        onClose={()=>{setEditType(null);setEditItem(null);}}/>}
    </>
  );
}

function SaudeSection({title,items,render,onAdd,onEdit,onDelete}){
  return (
    <Card style={{padding:"14px 16px",marginBottom:12}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:items.length?10:0}}>
        <span className="serif" style={{fontSize:15,fontWeight:700,color:T.text}}>{title}</span>
        <button onClick={onAdd} style={{
          fontSize:11,fontWeight:700,color:T.blue,padding:"4px 10px",borderRadius:99,
          background:T.blueBg,border:`1px solid ${T.blue}33`}}>+ Adicionar</button>
      </div>
      {items.length===0 ? (
        <div style={{fontSize:12,color:T.textMute,padding:"6px 0",fontStyle:"italic"}}>Nada registrado ainda.</div>
      ) : (
        <div style={{display:"flex",flexDirection:"column",gap:6}}>
          {items.map(item=>{
            const r=render(item);
            return (
              <div key={item.id} style={{padding:"8px 10px",borderRadius:8,background:T.bgInput,
                display:"flex",alignItems:"center",gap:8}}>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontSize:13,fontWeight:700,color:T.text}}>{r.primary}</div>
                  <div style={{fontSize:11,color:T.textMute,marginTop:1}}>{r.secondary}</div>
                  {r.next && <div style={{fontSize:11,color:T.blue,marginTop:1,fontWeight:600}}>{r.next}</div>}
                </div>
                <IconBtn icon="✏️" onClick={()=>onEdit(item)}/>
                <IconBtn icon="🗑️" onClick={()=>onDelete(item.id)}/>
              </div>
            );
          })}
        </div>
      )}
    </Card>
  );
}

function SaudeEditModal({type,item,pet,update,onClose}){
  const defaults={
    vacina:{nome:"",data:"",proxima:"",lote:""},
    vermifugo:{produto:"",data:"",proxima:""},
    antipulga:{produto:"",data:"",proxima:""},
    consulta:{data:"",motivo:"",vet:"",observacoes:""},
    exame:{tipo:"",data:"",resultado:""},
    cirurgia:{tipo:"",data:"",observacoes:""},
    medicamento:{nome:"",dose:"",frequencia:""},
  };
  const titles={vacina:"Vacina",vermifugo:"Vermífugo",antipulga:"Antipulga",
    consulta:"Consulta",exame:"Exame",cirurgia:"Cirurgia",medicamento:"Medicamento"};
  const fields={
    vacina:[{k:"nome",l:"Nome"},{k:"data",l:"Data aplicada",p:"dd/mm/aaaa"},{k:"proxima",l:"Próxima",p:"dd/mm/aaaa"},{k:"lote",l:"Lote (opcional)"}],
    vermifugo:[{k:"produto",l:"Produto"},{k:"data",l:"Data",p:"dd/mm/aaaa"},{k:"proxima",l:"Próxima",p:"dd/mm/aaaa"}],
    antipulga:[{k:"produto",l:"Produto"},{k:"data",l:"Data",p:"dd/mm/aaaa"},{k:"proxima",l:"Próxima",p:"dd/mm/aaaa"}],
    consulta:[{k:"data",l:"Data",p:"dd/mm/aaaa"},{k:"motivo",l:"Motivo"},{k:"vet",l:"Veterinário"},{k:"observacoes",l:"Observações"}],
    exame:[{k:"tipo",l:"Tipo de exame"},{k:"data",l:"Data",p:"dd/mm/aaaa"},{k:"resultado",l:"Resultado"}],
    cirurgia:[{k:"tipo",l:"Tipo de cirurgia"},{k:"data",l:"Data",p:"dd/mm/aaaa"},{k:"observacoes",l:"Observações"}],
    medicamento:[{k:"nome",l:"Nome"},{k:"dose",l:"Dose"},{k:"frequencia",l:"Frequência"}],
  };
  const fieldKey={vacina:"vacinas",vermifugo:"vermifugos",antipulga:"antipulgas",
    consulta:"consultas",exame:"exames",cirurgia:"cirurgias",medicamento:"medicamentos"};

  const [form,setForm]=useState(item||defaults[type]);
  const salvar=()=>{
    const k=fieldKey[type];
    const list=pet[k]||[];
    if(item){update({[k]:list.map(x=>x.id===item.id?{...x,...form}:x)});}
    else{update({[k]:[...list,{...form,id:Date.now()}]});}
    onClose();
  };

  return (
    <Modal title={`${item?"Editar":"Novo"} ${titles[type]}`} onClose={onClose}>
      <div style={{display:"flex",flexDirection:"column",gap:12}}>
        {fields[type].map(f=>(
          <Input key={f.k} label={f.l} value={form[f.k]||""}
            onChange={e=>setForm(x=>({...x,[f.k]:e.target.value}))}
            placeholder={f.p}/>
        ))}
        <ModalActions onCancel={onClose} onSave={salvar} color={T.blue}
          saveLabel={item?"Salvar":"Adicionar"}/>
      </div>
    </Modal>
  );
}

function PetRotina({pet,update}){
  const [addBanho,setAddBanho]=useState(false);
  const [data,setData]=useState("");
  const adicionarBanho=()=>{
    if(!data.trim())return;
    update({banhos:[...pet.banhos,{id:Date.now(),data:data.trim()}]});
    setData("");setAddBanho(false);
  };
  const deletar=id=>update({banhos:pet.banhos.filter(b=>b.id!==id)});
  const ultimoBanho=pet.banhos[pet.banhos.length-1];
  const diasDesde=ultimoBanho?daysSince(ultimoBanho.data):null;

  return(
    <>
      <Card style={{padding:"14px 16px",marginBottom:12}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
          <span className="serif" style={{fontSize:15,fontWeight:700}}>🛁 Banhos</span>
          <button onClick={()=>setAddBanho(true)} style={{
            fontSize:11,fontWeight:700,color:T.blue,padding:"4px 10px",borderRadius:99,
            background:T.blueBg,border:`1px solid ${T.blue}33`}}>+ Registrar</button>
        </div>
        {ultimoBanho ? (
          <>
            <div style={{padding:"10px 12px",background:T.blueBg,borderRadius:10,marginBottom:8}}>
              <div style={{fontSize:11,color:T.textMute,fontWeight:700,letterSpacing:.3}}>ÚLTIMO BANHO</div>
              <div className="serif" style={{fontSize:17,fontWeight:700,color:T.blue,marginTop:2}}>
                {diasDesde===0?"Hoje":diasDesde===1?"Ontem":`${diasDesde} dias atrás`}
              </div>
              <div style={{fontSize:12,color:T.textSub,marginTop:1}}>{ultimoBanho.data}</div>
            </div>
            <div style={{fontSize:11,fontWeight:700,color:T.textMute,marginBottom:6}}>HISTÓRICO</div>
            <div style={{display:"flex",flexDirection:"column",gap:4}}>
              {[...pet.banhos].reverse().map(b=>(
                <div key={b.id} style={{display:"flex",alignItems:"center",gap:8,
                  padding:"6px 10px",background:T.bgInput,borderRadius:8}}>
                  <span style={{fontSize:12,color:T.text,flex:1}}>{b.data}</span>
                  <IconBtn icon="🗑️" onClick={()=>deletar(b.id)} size={13}/>
                </div>
              ))}
            </div>
          </>
        ) : (
          <div style={{fontSize:12,color:T.textMute,padding:"6px 0",fontStyle:"italic"}}>Nenhum banho registrado.</div>
        )}
      </Card>

      {addBanho && (
        <Modal title="Registrar Banho" onClose={()=>setAddBanho(false)}>
          <div style={{display:"flex",flexDirection:"column",gap:12}}>
            <Input label="Data" value={data} onChange={e=>setData(e.target.value)} placeholder="dd/mm/aaaa"/>
            <ModalActions onCancel={()=>setAddBanho(false)} onSave={adicionarBanho} color={T.blue}/>
          </div>
        </Modal>
      )}
    </>
  );
}

function PetGaleria({pet,update}){
  const fileRef=useRef();
  const [view,setView]=useState(null);
  const handleFoto=async e=>{
    const f=e.target.files[0]; if(!f) return;
    const data=await compressImage(f,1024,0.85);
    update({galeria:[...(pet.galeria||[]),{id:Date.now(),foto:data,data:now.toLocaleDateString("pt-BR")}]});
  };
  const remover=id=>update({galeria:pet.galeria.filter(g=>g.id!==id)});

  return(
    <>
      <Card style={{padding:"14px 16px"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
          <span className="serif" style={{fontSize:15,fontWeight:700}}>📸 Álbum de {pet.nome}</span>
          <button onClick={()=>fileRef.current.click()} style={{
            fontSize:11,fontWeight:700,color:T.blue,padding:"4px 10px",borderRadius:99,
            background:T.blueBg,border:`1px solid ${T.blue}33`}}>+ Foto</button>
        </div>
        <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={handleFoto}/>
        {(!pet.galeria||pet.galeria.length===0) ? (
          <div style={{textAlign:"center",padding:"24px 0",fontSize:13,color:T.textMute,fontStyle:"italic"}}>
            Adicione fotos para criar o álbum do {pet.nome}
          </div>
        ) : (
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:6}}>
            {pet.galeria.map(g=>(
              <button key={g.id} onClick={()=>setView(g)} style={{
                aspectRatio:"1",borderRadius:8,overflow:"hidden",
                border:`1px solid ${T.border}`,padding:0,background:"none"}}>
                <img src={g.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
              </button>
            ))}
          </div>
        )}
      </Card>
      {view && (
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.85)",zIndex:700,
          display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:20}}
          onClick={()=>setView(null)}>
          <img src={view.foto} alt="" style={{maxWidth:"100%",maxHeight:"70%",borderRadius:14}}/>
          <div style={{color:"#fff",marginTop:14,fontSize:13}}>{view.data}</div>
          <button onClick={(e)=>{e.stopPropagation();remover(view.id);setView(null);}} style={{
            marginTop:18,padding:"8px 18px",borderRadius:99,
            background:T.dangerBg,color:T.danger,fontSize:13,fontWeight:700}}>🗑️ Remover</button>
        </div>
      )}
    </>
  );
}

function PetGastos({pet,update}){
  const [add,setAdd]=useState(false);
  const [form,setForm]=useState({categoria:"Veterinário",valor:"",data:"",descricao:""});
  const cats=["Veterinário","Ração","Medicamentos","Banho e tosa","Acessórios","Outros"];

  const adicionar=()=>{
    if(!form.valor)return;
    update({gastos:[...(pet.gastos||[]),{id:Date.now(),...form,valor:parseFloat(form.valor)||0}]});
    setForm({categoria:"Veterinário",valor:"",data:"",descricao:""});
    setAdd(false);
  };
  const remover=id=>update({gastos:pet.gastos.filter(g=>g.id!==id)});

  const total=(pet.gastos||[]).reduce((s,g)=>s+(g.valor||0),0);
  const porCat={};
  (pet.gastos||[]).forEach(g=>{porCat[g.categoria]=(porCat[g.categoria]||0)+(g.valor||0);});

  return(
    <>
      <Card style={{padding:"14px 16px",marginBottom:12,background:T.blueBg,border:`1px solid ${T.blue}22`}}>
        <div style={{fontSize:11,color:T.textMute,fontWeight:700,letterSpacing:.3}}>TOTAL GASTO</div>
        <div className="serif" style={{fontSize:28,fontWeight:700,color:T.blue,marginTop:2,letterSpacing:-.4}}>
          R$ {total.toFixed(2).replace(".",",")}
        </div>
        {Object.keys(porCat).length>0 && (
          <div style={{display:"flex",flexDirection:"column",gap:4,marginTop:10}}>
            {Object.entries(porCat).map(([c,v])=>(
              <div key={c} style={{display:"flex",justifyContent:"space-between",fontSize:12}}>
                <span style={{color:T.textSub}}>{c}</span>
                <span style={{fontWeight:700,color:T.text}}>R$ {v.toFixed(2).replace(".",",")}</span>
              </div>
            ))}
          </div>
        )}
      </Card>

      <Card style={{padding:"14px 16px"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
          <span className="serif" style={{fontSize:15,fontWeight:700}}>💰 Histórico</span>
          <button onClick={()=>setAdd(true)} style={{
            fontSize:11,fontWeight:700,color:T.blue,padding:"4px 10px",borderRadius:99,
            background:T.blueBg,border:`1px solid ${T.blue}33`}}>+ Gasto</button>
        </div>
        {(!pet.gastos||pet.gastos.length===0) ? (
          <div style={{fontSize:12,color:T.textMute,padding:"6px 0",fontStyle:"italic"}}>Nenhum gasto registrado.</div>
        ) : (
          <div style={{display:"flex",flexDirection:"column",gap:6}}>
            {[...pet.gastos].reverse().map(g=>(
              <div key={g.id} style={{padding:"8px 10px",borderRadius:8,background:T.bgInput,
                display:"flex",alignItems:"center",gap:8}}>
                <div style={{flex:1}}>
                  <div style={{fontSize:12,fontWeight:700}}>{g.categoria}</div>
                  <div style={{fontSize:11,color:T.textMute,marginTop:1}}>{g.data} {g.descricao&&`· ${g.descricao}`}</div>
                </div>
                <div style={{fontSize:13,fontWeight:800,color:T.blue}}>R$ {(g.valor||0).toFixed(2).replace(".",",")}</div>
                <IconBtn icon="🗑️" onClick={()=>remover(g.id)} size={13}/>
              </div>
            ))}
          </div>
        )}
      </Card>

      {add && (
        <Modal title="Novo Gasto" onClose={()=>setAdd(false)}>
          <div style={{display:"flex",flexDirection:"column",gap:12}}>
            <Select label="Categoria" value={form.categoria} onChange={e=>setForm(f=>({...f,categoria:e.target.value}))} options={cats}/>
            <Input label="Valor" type="number" value={form.valor} onChange={e=>setForm(f=>({...f,valor:e.target.value}))} placeholder="0,00"/>
            <Input label="Data" value={form.data} onChange={e=>setForm(f=>({...f,data:e.target.value}))} placeholder="dd/mm/aaaa"/>
            <Input label="Descrição" value={form.descricao} onChange={e=>setForm(f=>({...f,descricao:e.target.value}))}/>
            <ModalActions onCancel={()=>setAdd(false)} onSave={adicionar} color={T.blue}/>
          </div>
        </Modal>
      )}
    </>
  );
}

function PetHistorico({pet}){
  const eventos=[];
  pet.vacinas.forEach(v=>eventos.push({tipo:"💉 Vacina",titulo:v.nome,data:v.data}));
  pet.vermifugos.forEach(v=>eventos.push({tipo:"🪱 Vermífugo",titulo:v.produto,data:v.data}));
  pet.antipulgas.forEach(v=>eventos.push({tipo:"🐛 Antipulga",titulo:v.produto,data:v.data}));
  pet.consultas.forEach(v=>eventos.push({tipo:"🩺 Consulta",titulo:v.motivo||"Consulta",data:v.data}));
  pet.exames.forEach(v=>eventos.push({tipo:"🔬 Exame",titulo:v.tipo,data:v.data}));
  (pet.cirurgias||[]).forEach(v=>eventos.push({tipo:"✂️ Cirurgia",titulo:v.tipo,data:v.data}));
  pet.banhos.forEach(v=>eventos.push({tipo:"🛁 Banho",titulo:"Banho",data:v.data}));

  const sorted=eventos.sort((a,b)=>{
    const da=parseDate(a.data); const db=parseDate(b.data);
    if(!da||!db)return 0;return db-da;
  });

  if(sorted.length===0){
    return (
      <Card style={{padding:"24px",textAlign:"center"}}>
        <div style={{fontSize:13,color:T.textMute,fontStyle:"italic"}}>Nenhum evento registrado ainda.</div>
      </Card>
    );
  }
  return(
    <Card style={{padding:"14px 16px"}}>
      <div className="serif" style={{fontSize:15,fontWeight:700,marginBottom:14}}>📅 Linha do tempo</div>
      <div style={{position:"relative",paddingLeft:18}}>
        <div style={{position:"absolute",left:5,top:5,bottom:5,width:2,background:T.border}}/>
        {sorted.map((ev,i)=>(
          <div key={i} style={{position:"relative",marginBottom:14}}>
            <div style={{position:"absolute",left:-18,top:4,width:12,height:12,borderRadius:"50%",
              background:T.blue,border:`2px solid ${T.bgCard}`}}/>
            <div style={{fontSize:11,color:T.textMute,fontWeight:600}}>{ev.data}</div>
            <div style={{fontSize:13,fontWeight:700,color:T.text,marginTop:1}}>
              {ev.tipo}: {ev.titulo}
            </div>
          </div>
        ))}
      </div>
    </Card>
  );
}

/* ════════════════════════════════════════════════════════════════════════════
   TELA CLOSET — Peças + Looks + Estatísticas
═══════════════════════════════════════════════════════════════════════════ */
const CLOSET_CATEGORIAS=["Vestido","Camisa","Blusa","Calça","Saia","Sapato","Acessório","Casaco","Bolsa","Outro"];
const CLOSET_OCASIOES=["Trabalho","Casual","Congresso","Viagem","Evento","Plantão","Festa"];
const CLOSET_ESTACOES=["Verão","Outono","Inverno","Primavera","Todas"];

function TelaCloset({pecas,setPecas,looks,setLooks,onMenu}){
  const [tab,setTab]=useState("looks");
  const [addPeca,setAddPeca]=useState(false);
  const [addLook,setAddLook]=useState(false);
  const [editPeca,setEditPeca]=useState(null);
  const [editLook,setEditLook]=useState(null);
  const [filtro,setFiltro]=useState("Todos");

  return(
    <div style={{display:"flex",flexDirection:"column",height:"100%"}}>
      <AppHeader title="Closet" onMenu={onMenu}/>
      <div style={{flex:1,overflowY:"auto",padding:"14px 16px 100px"}}>
        <MascoteHeader secao="closet" sub="Diário de estilo"/>

        <div style={{display:"flex",background:T.bgInput,borderRadius:11,padding:3,gap:3,marginBottom:14,overflowX:"auto"}}>
          {[
            {id:"looks",l:`👗 Looks (${looks.length})`},
            {id:"pecas",l:`👚 Peças (${pecas.length})`},
            {id:"stats",l:`📊 Estatísticas`},
          ].map(t=>(
            <button key={t.id} onClick={()=>setTab(t.id)} style={{
              flex:"1 0 auto",padding:"7px 14px",borderRadius:8,fontSize:12,fontWeight:700,
              background:tab===t.id?T.bgCard:"transparent",
              border:tab===t.id?`1px solid ${T.border}`:"none",
              color:tab===t.id?T.text:T.textMute,whiteSpace:"nowrap"}}>{t.l}</button>
          ))}
        </div>

        {tab==="looks" && <>
          {/* Filtros por ocasião */}
          {looks.length>0 && (
            <div style={{display:"flex",gap:6,overflowX:"auto",marginBottom:12,paddingBottom:4}}>
              {["Todos","Favoritos",...CLOSET_OCASIOES].map(c=>(
                <button key={c} onClick={()=>setFiltro(c)} style={{
                  padding:"5px 11px",borderRadius:99,fontSize:11,fontWeight:700,
                  background:filtro===c?T.sand:T.bgCard,color:filtro===c?"#fff":T.textSub,
                  border:`1px solid ${filtro===c?T.sand:T.border}`,
                  whiteSpace:"nowrap",flexShrink:0}}>{c}</button>
              ))}
            </div>
          )}

          {(()=>{
            let f=looks;
            if(filtro==="Favoritos") f=looks.filter(l=>l.favorito);
            else if(filtro!=="Todos") f=looks.filter(l=>l.ocasiao===filtro);
            return looks.length===0 ? (
              <Card style={{padding:"30px 20px",textAlign:"center"}}>
                <img src={COW_LOLA} alt="" style={{width:80,height:80,objectFit:"contain",marginBottom:10}}/>
                <div className="serif" style={{fontSize:16,fontWeight:700,marginBottom:4}}>"Vamos começar?"</div>
                <div style={{fontSize:12,color:T.textMute,fontStyle:"italic"}}>— Lola</div>
              </Card>
            ) : f.length===0 ? (
              <Card style={{padding:"24px",textAlign:"center"}}>
                <div style={{fontSize:13,color:T.textMute}}>Nenhum look nesse filtro</div>
              </Card>
            ) : (
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:14}}>
                {f.map(l=>(
                  <button key={l.id} onClick={()=>setEditLook({...l})} style={{
                    borderRadius:14,overflow:"hidden",
                    background:T.bgCard,border:`1px solid ${T.border}`,
                    textAlign:"left",position:"relative"}}>
                    <div style={{aspectRatio:"3/4",background:T.sandBg,
                      display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden"}}>
                      {l.foto ? (
                        <img src={l.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
                      ) : (
                        <span style={{fontSize:36}}>👗</span>
                      )}
                    </div>
                    <div style={{padding:"8px 10px"}}>
                      <div style={{fontSize:12,fontWeight:700,color:T.text,
                        overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{l.titulo||"Sem título"}</div>
                      <div style={{fontSize:10,color:T.textMute,marginTop:2}}>
                        {l.ocasiao} · {l.data}
                      </div>
                    </div>
                    {l.favorito && (
                      <div style={{position:"absolute",top:6,right:6,fontSize:16}}>❤️</div>
                    )}
                  </button>
                ))}
              </div>
            );
          })()}
          <button onClick={()=>setAddLook(true)} style={{
            width:"100%",padding:"13px",borderRadius:12,
            background:T.sand,color:"#fff",fontSize:14,fontWeight:700,
            boxShadow:"0 2px 12px rgba(196,169,106,.3)"}}>+ Novo Look</button>
        </>}

        {tab==="pecas" && <>
          {pecas.length>0 && (
            <div style={{display:"flex",gap:6,overflowX:"auto",marginBottom:12,paddingBottom:4}}>
              {["Todos","Favoritos",...CLOSET_CATEGORIAS].map(c=>(
                <button key={c} onClick={()=>setFiltro(c)} style={{
                  padding:"5px 11px",borderRadius:99,fontSize:11,fontWeight:700,
                  background:filtro===c?T.sand:T.bgCard,color:filtro===c?"#fff":T.textSub,
                  border:`1px solid ${filtro===c?T.sand:T.border}`,
                  whiteSpace:"nowrap",flexShrink:0}}>{c}</button>
              ))}
            </div>
          )}
          {(()=>{
            let f=pecas;
            if(filtro==="Favoritos") f=pecas.filter(p=>p.favorito);
            else if(filtro!=="Todos") f=pecas.filter(p=>p.categoria===filtro);
            return f.length===0 ? (
              <Card style={{padding:"24px",textAlign:"center"}}>
                <div style={{fontSize:13,color:T.textMute}}>Nenhuma peça aqui</div>
              </Card>
            ) : (
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:14}}>
                {f.map(p=>(
                  <button key={p.id} onClick={()=>setEditPeca({...p})} style={{
                    borderRadius:12,overflow:"hidden",
                    background:T.bgCard,border:`1px solid ${T.border}`,
                    textAlign:"left",position:"relative"}}>
                    <div style={{aspectRatio:"1",background:T.sandBg,
                      display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden"}}>
                      {p.foto ? (
                        <img src={p.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
                      ) : (
                        <span style={{fontSize:30}}>👚</span>
                      )}
                    </div>
                    <div style={{padding:"8px 10px"}}>
                      <div style={{fontSize:12,fontWeight:700,color:T.text,
                        overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{p.nome}</div>
                      <div style={{fontSize:10,color:T.textMute,marginTop:2}}>
                        {p.categoria} · {p.cor}
                      </div>
                    </div>
                    {p.favorito && <div style={{position:"absolute",top:6,right:6,fontSize:14}}>❤️</div>}
                  </button>
                ))}
              </div>
            );
          })()}
          <button onClick={()=>setAddPeca(true)} style={{
            width:"100%",padding:"13px",borderRadius:12,
            background:T.sand,color:"#fff",fontSize:14,fontWeight:700,
            boxShadow:"0 2px 12px rgba(196,169,106,.3)"}}>+ Nova Peça</button>
        </>}

        {tab==="stats" && <ClosetStats pecas={pecas} looks={looks}/>}

      </div>

      {addPeca && <PecaModal onClose={()=>setAddPeca(false)}
        onSave={p=>{setPecas(ps=>[...ps,{id:Date.now(),...p,usos:0}]);setAddPeca(false);}}/>}
      {editPeca && <PecaModal peca={editPeca} onClose={()=>setEditPeca(null)}
        onSave={p=>{setPecas(ps=>ps.map(x=>x.id===editPeca.id?{...x,...p}:x));setEditPeca(null);}}
        onDelete={()=>{setPecas(ps=>ps.filter(x=>x.id!==editPeca.id));setEditPeca(null);}}/>}

      {addLook && <LookModal pecas={pecas} setPecas={setPecas} onClose={()=>setAddLook(false)}
        onSave={l=>{
          setLooks(ls=>[...ls,{id:Date.now(),...l}]);
          // incrementa usos
          if(l.pecasIds)setPecas(ps=>ps.map(p=>l.pecasIds.includes(p.id)?{...p,usos:(p.usos||0)+1}:p));
          setAddLook(false);
        }}/>}
      {editLook && <LookModal pecas={pecas} look={editLook} onClose={()=>setEditLook(null)}
        onSave={l=>{setLooks(ls=>ls.map(x=>x.id===editLook.id?{...x,...l}:x));setEditLook(null);}}
        onDelete={()=>{setLooks(ls=>ls.filter(x=>x.id!==editLook.id));setEditLook(null);}}/>}
    </div>
  );
}

function ClosetStats({pecas,looks}){
  // peças mais usadas
  const top=[...pecas].sort((a,b)=>(b.usos||0)-(a.usos||0)).slice(0,5);
  // cores
  const cores={};
  looks.forEach(l=>{
    (l.pecasIds||[]).forEach(pid=>{
      const p=pecas.find(x=>x.id===pid);
      if(p&&p.cor) cores[p.cor]=(cores[p.cor]||0)+1;
    });
  });
  const topCores=Object.entries(cores).sort((a,b)=>b[1]-a[1]).slice(0,5);
  const favLooks=looks.filter(l=>l.favorito);

  return (
    <div style={{display:"flex",flexDirection:"column",gap:12}}>
      <Card style={{padding:"14px 16px",background:T.sandBg,border:`1px solid ${T.sand}22`}}>
        <div style={{fontSize:11,color:T.textMute,fontWeight:700,letterSpacing:.3}}>RESUMO</div>
        <div style={{display:"flex",gap:14,marginTop:8}}>
          <div>
            <div className="serif" style={{fontSize:24,fontWeight:700,color:T.sand}}>{pecas.length}</div>
            <div style={{fontSize:10,color:T.textMute,fontWeight:600}}>peças</div>
          </div>
          <div>
            <div className="serif" style={{fontSize:24,fontWeight:700,color:T.sand}}>{looks.length}</div>
            <div style={{fontSize:10,color:T.textMute,fontWeight:600}}>looks</div>
          </div>
          <div>
            <div className="serif" style={{fontSize:24,fontWeight:700,color:T.sand}}>{favLooks.length}</div>
            <div style={{fontSize:10,color:T.textMute,fontWeight:600}}>favoritos</div>
          </div>
        </div>
      </Card>

      <Card style={{padding:"14px 16px"}}>
        <div className="serif" style={{fontSize:15,fontWeight:700,marginBottom:10}}>🏆 Peças mais usadas</div>
        {top.length===0 || top.every(p=>!p.usos) ? (
          <div style={{fontSize:12,color:T.textMute,fontStyle:"italic"}}>Registre looks para ver as peças mais usadas</div>
        ) : (
          <div style={{display:"flex",flexDirection:"column",gap:6}}>
            {top.filter(p=>p.usos).map((p,i)=>(
              <div key={p.id} style={{display:"flex",alignItems:"center",gap:10,
                padding:"6px 8px",background:T.bgInput,borderRadius:8}}>
                <span style={{fontSize:11,fontWeight:800,color:T.sand,width:18}}>#{i+1}</span>
                <span style={{flex:1,fontSize:13,fontWeight:600}}>{p.nome}</span>
                <Pill label={`${p.usos}x`} color={T.sand} bg={T.sandBg}/>
              </div>
            ))}
          </div>
        )}
      </Card>

      <Card style={{padding:"14px 16px"}}>
        <div className="serif" style={{fontSize:15,fontWeight:700,marginBottom:10}}>🎨 Cores mais utilizadas</div>
        {topCores.length===0 ? (
          <div style={{fontSize:12,color:T.textMute,fontStyle:"italic"}}>Crie looks para ver as cores mais usadas</div>
        ) : (
          <div style={{display:"flex",flexDirection:"column",gap:6}}>
            {topCores.map(([c,n])=>(
              <div key={c} style={{display:"flex",alignItems:"center",gap:10,
                padding:"6px 8px",background:T.bgInput,borderRadius:8}}>
                <span style={{flex:1,fontSize:13,fontWeight:600}}>{c}</span>
                <Pill label={`${n}x`} color={T.sand} bg={T.sandBg}/>
              </div>
            ))}
          </div>
        )}
      </Card>
    </div>
  );
}

function PecaModal({peca,onClose,onSave,onDelete}){
  const [form,setForm]=useState(peca||{nome:"",categoria:"Vestido",cor:"",ocasiao:"Casual",estacao:"Todas",foto:null,favorito:false});
  const fileRef=useRef();
  const handleFoto=async e=>{
    const f=e.target.files[0]; if(!f) return;
    const data=await compressImage(f,800,0.85);
    setForm(x=>({...x,foto:data}));
  };
  return (
    <Modal title={peca?"Editar Peça":"Nova Peça"} onClose={onClose}>
      <div style={{display:"flex",flexDirection:"column",gap:12}}>
        <button onClick={()=>fileRef.current.click()} style={{
          width:"100%",aspectRatio:"1",maxHeight:200,borderRadius:14,
          background:T.sandBg,border:`2px dashed ${form.foto?T.sand:T.borderMd}`,
          display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden"}}>
          {form.foto ? (
            <img src={form.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
          ) : (
            <div style={{textAlign:"center",color:T.textMute}}>
              <div style={{fontSize:32}}>📷</div>
              <div style={{fontSize:12,fontWeight:600,marginTop:6}}>Toque para foto</div>
            </div>
          )}
        </button>
        <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={handleFoto}/>
        <Input label="Nome" value={form.nome} onChange={e=>setForm(f=>({...f,nome:e.target.value}))}/>
        <div style={{display:"flex",gap:10}}>
          <div style={{flex:1}}>
            <Select label="Categoria" value={form.categoria} onChange={e=>setForm(f=>({...f,categoria:e.target.value}))} options={CLOSET_CATEGORIAS}/>
          </div>
          <div style={{flex:1}}>
            <Input label="Cor" value={form.cor} onChange={e=>setForm(f=>({...f,cor:e.target.value}))}/>
          </div>
        </div>
        <div style={{display:"flex",gap:10}}>
          <div style={{flex:1}}>
            <Select label="Ocasião" value={form.ocasiao} onChange={e=>setForm(f=>({...f,ocasiao:e.target.value}))} options={CLOSET_OCASIOES}/>
          </div>
          <div style={{flex:1}}>
            <Select label="Estação" value={form.estacao} onChange={e=>setForm(f=>({...f,estacao:e.target.value}))} options={CLOSET_ESTACOES}/>
          </div>
        </div>
        <label style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer",
          padding:"10px 12px",borderRadius:10,background:T.bgInput,border:`1px solid ${T.border}`}}>
          <input type="checkbox" checked={form.favorito} onChange={e=>setForm(f=>({...f,favorito:e.target.checked}))}/>
          <span style={{fontSize:13,fontWeight:600}}>❤️ Favorita</span>
        </label>
        <ModalActions onCancel={onClose} onSave={()=>onSave(form)} onDelete={onDelete} color={T.sand}/>
      </div>
    </Modal>
  );
}

function LookModal({look,pecas,onClose,onSave,onDelete}){
  const [form,setForm]=useState(look||{titulo:"",ocasiao:"Trabalho",local:"",
    data:now.toLocaleDateString("pt-BR"),foto:null,pecasIds:[],notas:"",favorito:false});
  const fileRef=useRef();
  const handleFoto=async e=>{
    const f=e.target.files[0]; if(!f) return;
    const data=await compressImage(f,1024,0.85);
    setForm(x=>({...x,foto:data}));
  };
  const togglePeca=id=>{
    setForm(f=>({...f,pecasIds:f.pecasIds.includes(id)?f.pecasIds.filter(x=>x!==id):[...f.pecasIds,id]}));
  };
  return (
    <Modal title={look?"Editar Look":"Novo Look"} onClose={onClose}>
      <div style={{display:"flex",flexDirection:"column",gap:12}}>
        <button onClick={()=>fileRef.current.click()} style={{
          width:"100%",aspectRatio:"3/4",maxHeight:260,borderRadius:14,
          background:T.sandBg,border:`2px dashed ${form.foto?T.sand:T.borderMd}`,
          display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden"}}>
          {form.foto ? (
            <img src={form.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
          ) : (
            <div style={{textAlign:"center",color:T.textMute}}>
              <div style={{fontSize:34}}>📷</div>
              <div style={{fontSize:12,fontWeight:600,marginTop:6}}>Foto do look</div>
            </div>
          )}
        </button>
        <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={handleFoto}/>
        <Input label="Título" value={form.titulo} onChange={e=>setForm(f=>({...f,titulo:e.target.value}))}/>
        <div style={{display:"flex",gap:10}}>
          <div style={{flex:1}}>
            <Select label="Ocasião" value={form.ocasiao} onChange={e=>setForm(f=>({...f,ocasiao:e.target.value}))} options={CLOSET_OCASIOES}/>
          </div>
          <div style={{flex:1}}>
            <Input label="Data" value={form.data} onChange={e=>setForm(f=>({...f,data:e.target.value}))}/>
          </div>
        </div>
        <Input label="Local (opcional)" value={form.local} onChange={e=>setForm(f=>({...f,local:e.target.value}))}/>
        {pecas.length>0 && (
          <div>
            <div style={{fontSize:11,color:T.textMute,fontWeight:700,marginBottom:5,letterSpacing:.3}}>PEÇAS USADAS</div>
            <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
              {pecas.map(p=>{
                const sel=form.pecasIds.includes(p.id);
                return (
                  <button key={p.id} onClick={()=>togglePeca(p.id)} style={{
                    padding:"5px 10px",borderRadius:99,fontSize:11,fontWeight:700,
                    background:sel?T.sand:T.bgInput,color:sel?"#fff":T.textSub,
                    border:`1px solid ${sel?T.sand:T.border}`}}>{p.nome}</button>
                );
              })}
            </div>
          </div>
        )}
        <div>
          <div style={{fontSize:11,color:T.textMute,fontWeight:700,marginBottom:5,letterSpacing:.3}}>NOTAS</div>
          <textarea value={form.notas} onChange={e=>setForm(f=>({...f,notas:e.target.value}))} rows={2}
            placeholder="Como você se sentiu..."
            style={{width:"100%",padding:"10px 13px",borderRadius:10,
              border:`1px solid ${T.border}`,background:T.bgInput,fontSize:13,color:T.text,resize:"none"}}/>
        </div>
        <label style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer",
          padding:"10px 12px",borderRadius:10,background:T.bgInput,border:`1px solid ${T.border}`}}>
          <input type="checkbox" checked={form.favorito} onChange={e=>setForm(f=>({...f,favorito:e.target.checked}))}/>
          <span style={{fontSize:13,fontWeight:600}}>❤️ Favorito</span>
        </label>
        <ModalActions onCancel={onClose} onSave={()=>onSave(form)} onDelete={onDelete} color={T.sand}/>
      </div>
    </Modal>
  );
}

/* ════════════════════════════════════════════════════════════════════════════
   TELA BEAUTY — Beauty Journal (Maquiagem) + Skincare
═══════════════════════════════════════════════════════════════════════════ */
const BEAUTY_CATEGORIAS=["Base","Corretivo","Blush","Batom","Sombra","Iluminador","Bronzer","Perfume","Outro"];
const SKINCARE_CATEGORIAS=["Limpeza","Sérum","Retinol","Hidratante","Vitamina C","Ácidos","Protetor solar","Máscaras"];

function TelaBeauty({produtos,setProdutos,makes,setMakes,skProdutos,setSkProdutos,skDiario,setSkDiario,onMenu}){
  const [tab,setTab]=useState("makeup"); // makeup | skincare

  return(
    <div style={{display:"flex",flexDirection:"column",height:"100%"}}>
      <AppHeader title="Beauty" onMenu={onMenu}/>
      <div style={{flex:1,overflowY:"auto",padding:"14px 16px 100px"}}>
        <MascoteHeader secao="beauty" sub="Maquiagem e cuidados com a pele"/>

        {/* Sub-tabs maquiagem/skincare */}
        <div style={{display:"flex",background:T.bgInput,borderRadius:11,padding:3,gap:3,marginBottom:14}}>
          {[{id:"makeup",l:"💄 Maquiagem"},{id:"skincare",l:"🧴 Skincare"}].map(t=>(
            <button key={t.id} onClick={()=>setTab(t.id)} style={{
              flex:1,padding:"7px 0",borderRadius:8,fontSize:13,fontWeight:700,
              background:tab===t.id?T.bgCard:"transparent",
              border:tab===t.id?`1px solid ${T.border}`:"none",
              color:tab===t.id?T.text:T.textMute,transition:"all .15s"}}>{t.l}</button>
          ))}
        </div>

        {tab==="makeup" && <MakeupSection produtos={produtos} setProdutos={setProdutos}
          makes={makes} setMakes={setMakes}/>}
        {tab==="skincare" && <SkincareSection skProdutos={skProdutos} setSkProdutos={setSkProdutos}
          skDiario={skDiario} setSkDiario={setSkDiario}/>}
      </div>
    </div>
  );
}

function MakeupSection({produtos,setProdutos,makes,setMakes}){
  const [subtab,setSubtab]=useState("inventario");
  const [filtro,setFiltro]=useState("Todos");
  const [addProd,setAddProd]=useState(false);
  const [editProd,setEditProd]=useState(null);
  const [addMake,setAddMake]=useState(false);
  const [editMake,setEditMake]=useState(null);

  // Favoritos por categoria
  const favoritosPorCat=BEAUTY_CATEGORIAS.map(cat=>{
    const items=produtos.filter(p=>p.categoria===cat);
    const top=items.sort((a,b)=>(b.rating||0)-(a.rating||0))[0];
    return top?{cat,produto:top}:null;
  }).filter(Boolean);

  return (
    <>
      <div style={{display:"flex",background:T.bgInput,borderRadius:11,padding:3,gap:3,marginBottom:14}}>
        {[
          {id:"inventario",l:`💄 Inventário (${produtos.length})`},
          {id:"diario",l:`📔 Diário (${makes.length})`},
          {id:"favoritos",l:"⭐ Favoritos"},
        ].map(t=>(
          <button key={t.id} onClick={()=>setSubtab(t.id)} style={{
            flex:1,padding:"7px 4px",borderRadius:8,fontSize:11,fontWeight:700,
            background:subtab===t.id?T.bgCard:"transparent",
            border:subtab===t.id?`1px solid ${T.border}`:"none",
            color:subtab===t.id?T.text:T.textMute}}>{t.l}</button>
        ))}
      </div>

      {subtab==="inventario" && <>
        <div style={{display:"flex",gap:6,overflowX:"auto",marginBottom:12,paddingBottom:4}}>
          {["Todos","Favoritos",...BEAUTY_CATEGORIAS].map(c=>(
            <button key={c} onClick={()=>setFiltro(c)} style={{
              padding:"5px 11px",borderRadius:99,fontSize:11,fontWeight:700,
              background:filtro===c?T.rose:T.bgCard,color:filtro===c?"#fff":T.textSub,
              border:`1px solid ${filtro===c?T.rose:T.border}`,
              whiteSpace:"nowrap",flexShrink:0}}>{c}</button>
          ))}
        </div>
        {(()=>{
          let f=produtos;
          if(filtro==="Favoritos") f=produtos.filter(p=>p.favorito);
          else if(filtro!=="Todos") f=produtos.filter(p=>p.categoria===filtro);
          return f.length===0 ? (
            <Card style={{padding:"24px",textAlign:"center"}}>
              <div style={{fontSize:13,color:T.textMute}}>Nenhum produto aqui</div>
            </Card>
          ) : (
            <div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:14}}>
              {f.map(p=>(
                <button key={p.id} onClick={()=>setEditProd({...p})} style={{
                  display:"flex",alignItems:"center",gap:12,padding:"12px 14px",
                  borderRadius:12,background:T.bgCard,border:`1px solid ${T.border}`,
                  textAlign:"left"}}>
                  <div style={{width:48,height:48,borderRadius:10,background:T.roseBg,
                    display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden",flexShrink:0}}>
                    {p.foto ? (
                      <img src={p.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
                    ) : (
                      <span style={{fontSize:11,fontWeight:800,color:T.rose}}>{p.categoria.slice(0,4)}</span>
                    )}
                  </div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:14,fontWeight:700}}>{p.nome}</div>
                    <div style={{fontSize:11,color:T.textMute,marginTop:1}}>
                      {p.marca}{p.cor?` · ${p.cor}`:""}
                    </div>
                  </div>
                  <div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:2}}>
                    <div style={{fontSize:11,color:T.sand}}>
                      {"★".repeat(p.rating||0)}{"☆".repeat(5-(p.rating||0))}
                    </div>
                    {p.favorito && <span style={{fontSize:14}}>❤️</span>}
                  </div>
                </button>
              ))}
            </div>
          );
        })()}
        <button onClick={()=>setAddProd(true)} style={{
          width:"100%",padding:"13px",borderRadius:12,
          background:T.rose,color:"#fff",fontSize:14,fontWeight:700,
          boxShadow:"0 2px 12px rgba(176,122,122,.3)"}}>+ Novo Produto</button>
      </>}

      {subtab==="diario" && <>
        {makes.length===0 ? (
          <Card style={{padding:"30px 20px",textAlign:"center"}}>
            <img src={COW_CAMELIA} alt="" style={{width:80,height:80,objectFit:"contain",marginBottom:10}}/>
            <div className="serif" style={{fontSize:16,fontWeight:700,marginBottom:4}}>"Vamos cuidar de você?"</div>
            <div style={{fontSize:12,color:T.textMute,fontStyle:"italic"}}>— Camélia</div>
          </Card>
        ) : (
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:14}}>
            {makes.map(m=>(
              <button key={m.id} onClick={()=>setEditMake({...m})} style={{
                borderRadius:12,overflow:"hidden",background:T.bgCard,
                border:`1px solid ${T.border}`,textAlign:"left",position:"relative"}}>
                <div style={{aspectRatio:"1",background:T.roseBg,
                  display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden"}}>
                  {m.foto ? (
                    <img src={m.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
                  ) : (
                    <span style={{fontSize:36}}>💄</span>
                  )}
                </div>
                <div style={{padding:"8px 10px"}}>
                  <div style={{fontSize:12,fontWeight:700,
                    overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{m.titulo}</div>
                  <div style={{fontSize:10,color:T.textMute,marginTop:2}}>{m.data}</div>
                </div>
              </button>
            ))}
          </div>
        )}
        <button onClick={()=>setAddMake(true)} style={{
          width:"100%",padding:"13px",borderRadius:12,
          background:T.rose,color:"#fff",fontSize:14,fontWeight:700,
          boxShadow:"0 2px 12px rgba(176,122,122,.3)"}}>+ Nova Make</button>
      </>}

      {subtab==="favoritos" && <>
        {favoritosPorCat.length===0 ? (
          <Card style={{padding:"24px",textAlign:"center"}}>
            <div style={{fontSize:13,color:T.textMute,fontStyle:"italic"}}>Adicione produtos com avaliação para ver os favoritos</div>
          </Card>
        ) : (
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
            {favoritosPorCat.map(({cat,produto})=>(
              <Card key={cat} style={{padding:"12px 14px"}}>
                <div style={{fontSize:11,color:T.textMute,fontWeight:700,letterSpacing:.3,marginBottom:6}}>
                  MELHOR {cat.toUpperCase()}
                </div>
                <button onClick={()=>setEditProd({...produto})} style={{
                  display:"flex",alignItems:"center",gap:10,width:"100%",textAlign:"left"}}>
                  <div style={{width:44,height:44,borderRadius:10,background:T.roseBg,
                    display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden",flexShrink:0}}>
                    {produto.foto ? (
                      <img src={produto.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
                    ) : (
                      <span style={{fontSize:18}}>💄</span>
                    )}
                  </div>
                  <div style={{flex:1}}>
                    <div style={{fontSize:14,fontWeight:700}}>{produto.nome}</div>
                    <div style={{fontSize:11,color:T.textMute,marginTop:1}}>
                      {produto.marca} · {"★".repeat(produto.rating||0)}
                    </div>
                  </div>
                </button>
              </Card>
            ))}
          </div>
        )}
      </>}

      {addProd && <ProdutoModal onClose={()=>setAddProd(false)}
        onSave={p=>{setProdutos(ps=>[...ps,{id:Date.now(),...p}]);setAddProd(false);}}/>}
      {editProd && <ProdutoModal produto={editProd} onClose={()=>setEditProd(null)}
        onSave={p=>{setProdutos(ps=>ps.map(x=>x.id===editProd.id?{...x,...p}:x));setEditProd(null);}}
        onDelete={()=>{setProdutos(ps=>ps.filter(x=>x.id!==editProd.id));setEditProd(null);}}/>}

      {addMake && <MakeModal produtos={produtos} onClose={()=>setAddMake(false)}
        onSave={m=>{setMakes(ms=>[...ms,{id:Date.now(),...m}]);setAddMake(false);}}/>}
      {editMake && <MakeModal produtos={produtos} make={editMake} onClose={()=>setEditMake(null)}
        onSave={m=>{setMakes(ms=>ms.map(x=>x.id===editMake.id?{...x,...m}:x));setEditMake(null);}}
        onDelete={()=>{setMakes(ms=>ms.filter(x=>x.id!==editMake.id));setEditMake(null);}}/>}
    </>
  );
}

function ProdutoModal({produto,onClose,onSave,onDelete}){
  const [form,setForm]=useState(produto||{nome:"",categoria:"Batom",marca:"",cor:"",rating:5,foto:null,favorito:false,notas:""});
  const fileRef=useRef();
  const handleFoto=async e=>{
    const f=e.target.files[0]; if(!f) return;
    const data=await compressImage(f,600,0.85);
    setForm(x=>({...x,foto:data}));
  };
  return (
    <Modal title={produto?"Editar Produto":"Novo Produto"} onClose={onClose}>
      <div style={{display:"flex",flexDirection:"column",gap:12}}>
        <button onClick={()=>fileRef.current.click()} style={{
          width:80,height:80,alignSelf:"center",borderRadius:14,
          background:T.roseBg,border:`2px dashed ${form.foto?T.rose:T.borderMd}`,
          display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden"}}>
          {form.foto ? (
            <img src={form.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
          ) : (
            <span style={{fontSize:26}}>📷</span>
          )}
        </button>
        <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={handleFoto}/>
        <Input label="Nome" value={form.nome} onChange={e=>setForm(f=>({...f,nome:e.target.value}))}/>
        <div style={{display:"flex",gap:10}}>
          <div style={{flex:1}}>
            <Select label="Categoria" value={form.categoria} onChange={e=>setForm(f=>({...f,categoria:e.target.value}))} options={BEAUTY_CATEGORIAS}/>
          </div>
          <div style={{flex:1}}>
            <Input label="Marca" value={form.marca} onChange={e=>setForm(f=>({...f,marca:e.target.value}))}/>
          </div>
        </div>
        <Input label="Cor / Tom" value={form.cor} onChange={e=>setForm(f=>({...f,cor:e.target.value}))}/>
        <div>
          <div style={{fontSize:11,color:T.textMute,fontWeight:700,marginBottom:5,letterSpacing:.3}}>AVALIAÇÃO</div>
          <div style={{display:"flex",gap:4}}>
            {[1,2,3,4,5].map(n=>(
              <button key={n} onClick={()=>setForm(f=>({...f,rating:n}))} style={{fontSize:24,opacity:n<=form.rating?1:0.3,color:T.sand}}>★</button>
            ))}
          </div>
        </div>
        <label style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer",
          padding:"10px 12px",borderRadius:10,background:T.bgInput,border:`1px solid ${T.border}`}}>
          <input type="checkbox" checked={form.favorito} onChange={e=>setForm(f=>({...f,favorito:e.target.checked}))}/>
          <span style={{fontSize:13,fontWeight:600}}>❤️ Favorito</span>
        </label>
        <ModalActions onCancel={onClose} onSave={()=>onSave(form)} onDelete={onDelete} color={T.rose}/>
      </div>
    </Modal>
  );
}

function MakeModal({make,produtos,onClose,onSave,onDelete}){
  const [form,setForm]=useState(make||{titulo:"",data:now.toLocaleDateString("pt-BR"),evento:"",
    foto:null,produtosIds:[],notas:"",favorito:false,rating:5});
  const fileRef=useRef();
  const handleFoto=async e=>{
    const f=e.target.files[0]; if(!f) return;
    const data=await compressImage(f,1024,0.85);
    setForm(x=>({...x,foto:data}));
  };
  const toggleProd=id=>{
    setForm(f=>({...f,produtosIds:f.produtosIds.includes(id)?f.produtosIds.filter(x=>x!==id):[...f.produtosIds,id]}));
  };
  return (
    <Modal title={make?"Editar Make":"Nova Make"} onClose={onClose}>
      <div style={{display:"flex",flexDirection:"column",gap:12}}>
        <button onClick={()=>fileRef.current.click()} style={{
          width:"100%",aspectRatio:"1",maxHeight:240,borderRadius:14,
          background:T.roseBg,border:`2px dashed ${form.foto?T.rose:T.borderMd}`,
          display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden"}}>
          {form.foto ? (
            <img src={form.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
          ) : (
            <div style={{textAlign:"center",color:T.textMute}}>
              <div style={{fontSize:34}}>📷</div>
              <div style={{fontSize:12,fontWeight:600,marginTop:6}}>Foto da make</div>
            </div>
          )}
        </button>
        <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={handleFoto}/>
        <Input label="Título" value={form.titulo} onChange={e=>setForm(f=>({...f,titulo:e.target.value}))}/>
        <div style={{display:"flex",gap:10}}>
          <div style={{flex:1}}>
            <Input label="Data" value={form.data} onChange={e=>setForm(f=>({...f,data:e.target.value}))}/>
          </div>
          <div style={{flex:1}}>
            <Input label="Evento" value={form.evento} onChange={e=>setForm(f=>({...f,evento:e.target.value}))}/>
          </div>
        </div>
        <div>
          <div style={{fontSize:11,color:T.textMute,fontWeight:700,marginBottom:5,letterSpacing:.3}}>AVALIAÇÃO</div>
          <div style={{display:"flex",gap:4}}>
            {[1,2,3,4,5].map(n=>(
              <button key={n} onClick={()=>setForm(f=>({...f,rating:n}))} style={{fontSize:22,opacity:n<=form.rating?1:0.3,color:T.sand}}>★</button>
            ))}
          </div>
        </div>
        {produtos.length>0 && (
          <div>
            <div style={{fontSize:11,color:T.textMute,fontWeight:700,marginBottom:5,letterSpacing:.3}}>PRODUTOS USADOS</div>
            <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
              {produtos.map(p=>{
                const sel=form.produtosIds.includes(p.id);
                return (
                  <button key={p.id} onClick={()=>toggleProd(p.id)} style={{
                    padding:"5px 10px",borderRadius:99,fontSize:11,fontWeight:700,
                    background:sel?T.rose:T.bgInput,color:sel?"#fff":T.textSub,
                    border:`1px solid ${sel?T.rose:T.border}`}}>{p.nome}</button>
                );
              })}
            </div>
          </div>
        )}
        <div>
          <div style={{fontSize:11,color:T.textMute,fontWeight:700,marginBottom:5,letterSpacing:.3}}>OBSERVAÇÕES</div>
          <textarea value={form.notas} onChange={e=>setForm(f=>({...f,notas:e.target.value}))} rows={2}
            style={{width:"100%",padding:"10px 13px",borderRadius:10,
              border:`1px solid ${T.border}`,background:T.bgInput,fontSize:13,color:T.text,resize:"none"}}/>
        </div>
        <ModalActions onCancel={onClose} onSave={()=>onSave(form)} onDelete={onDelete} color={T.rose}/>
      </div>
    </Modal>
  );
}

/* === SKINCARE === */
function SkincareSection({skProdutos,setSkProdutos,skDiario,setSkDiario}){
  const [subtab,setSubtab]=useState("produtos");

  return (
    <>
      <div style={{display:"flex",background:T.bgInput,borderRadius:11,padding:3,gap:3,marginBottom:14}}>
        {[
          {id:"produtos",l:"🧴 Produtos"},
          {id:"diario",l:"📔 Diário"},
          {id:"evolucao",l:"📸 Evolução"},
        ].map(t=>(
          <button key={t.id} onClick={()=>setSubtab(t.id)} style={{
            flex:1,padding:"7px 4px",borderRadius:8,fontSize:11,fontWeight:700,
            background:subtab===t.id?T.bgCard:"transparent",
            border:subtab===t.id?`1px solid ${T.border}`:"none",
            color:subtab===t.id?T.text:T.textMute}}>{t.l}</button>
        ))}
      </div>

      {subtab==="produtos" && <SkincareProdutos produtos={skProdutos} setProdutos={setSkProdutos}/>}
      {subtab==="diario" && <SkincareDiario diario={skDiario} setDiario={setSkDiario}/>}
      {subtab==="evolucao" && <SkincareEvolucao diario={skDiario} produtos={skProdutos}/>}
    </>
  );
}

function SkincareProdutos({produtos,setProdutos}){
  const [add,setAdd]=useState(false);
  const [edit,setEdit]=useState(null);
  const [filtro,setFiltro]=useState("Todos");

  const ativos=produtos.filter(p=>!p.fim);
  const finalizados=produtos.filter(p=>p.fim);

  return (
    <>
      <Card style={{padding:"12px 14px",marginBottom:12,background:T.roseBg,border:`1px solid ${T.rose}22`}}>
        <div style={{fontSize:11,color:T.textMute,fontWeight:700}}>EM USO</div>
        <div className="serif" style={{fontSize:26,fontWeight:700,color:T.rose,marginTop:2,letterSpacing:-.3}}>
          {ativos.length} produto{ativos.length!==1?"s":""}
        </div>
      </Card>

      <div style={{display:"flex",gap:6,overflowX:"auto",marginBottom:12,paddingBottom:4}}>
        {["Todos",...SKINCARE_CATEGORIAS].map(c=>(
          <button key={c} onClick={()=>setFiltro(c)} style={{
            padding:"5px 11px",borderRadius:99,fontSize:11,fontWeight:700,
            background:filtro===c?T.rose:T.bgCard,color:filtro===c?"#fff":T.textSub,
            border:`1px solid ${filtro===c?T.rose:T.border}`,
            whiteSpace:"nowrap",flexShrink:0}}>{c}</button>
        ))}
      </div>

      <div style={{fontSize:11,color:T.textMute,fontWeight:700,marginBottom:6,letterSpacing:.3}}>
        ATUALMENTE EM USO
      </div>
      {(()=>{
        let f=ativos;
        if(filtro!=="Todos") f=ativos.filter(p=>p.categoria===filtro);
        return f.length===0 ? (
          <Card style={{padding:"16px",textAlign:"center"}}>
            <div style={{fontSize:12,color:T.textMute,fontStyle:"italic"}}>Nenhum produto em uso nesta categoria</div>
          </Card>
        ) : (
          <div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:14}}>
            {f.map(p=>{
              const dias=p.inicio?daysSince(p.inicio):null;
              return (
                <button key={p.id} onClick={()=>setEdit({...p})} style={{
                  display:"flex",alignItems:"center",gap:12,padding:"12px 14px",
                  borderRadius:12,background:T.bgCard,border:`1px solid ${T.border}`,
                  textAlign:"left"}}>
                  <div style={{width:48,height:48,borderRadius:10,background:T.roseBg,
                    display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden",flexShrink:0}}>
                    {p.foto ? (
                      <img src={p.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
                    ) : (
                      <span style={{fontSize:18}}>🧴</span>
                    )}
                  </div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:14,fontWeight:700}}>{p.nome}</div>
                    <div style={{fontSize:11,color:T.textMute,marginTop:1}}>{p.marca} · {p.categoria}</div>
                    <div style={{fontSize:10,color:T.rose,marginTop:2,fontWeight:600}}>{p.frequencia}</div>
                  </div>
                  {dias!==null&&dias>=0 && (
                    <Pill label={`${dias}d`} color={T.rose} bg={T.roseBg}/>
                  )}
                </button>
              );
            })}
          </div>
        );
      })()}

      {finalizados.length>0 && (
        <>
          <div style={{fontSize:11,color:T.textMute,fontWeight:700,marginBottom:6,letterSpacing:.3}}>
            FINALIZADOS
          </div>
          <div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:14}}>
            {finalizados.map(p=>(
              <button key={p.id} onClick={()=>setEdit({...p})} style={{
                display:"flex",alignItems:"center",gap:12,padding:"10px 14px",
                borderRadius:12,background:T.bgInput,opacity:.7,
                textAlign:"left"}}>
                <div style={{width:36,height:36,borderRadius:8,background:T.bgCard,
                  display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,flexShrink:0}}>
                  🧴
                </div>
                <div style={{flex:1}}>
                  <div style={{fontSize:13,fontWeight:600,textDecoration:"line-through"}}>{p.nome}</div>
                  <div style={{fontSize:10,color:T.textMute}}>{p.inicio} → {p.fim}</div>
                </div>
              </button>
            ))}
          </div>
        </>
      )}

      <button onClick={()=>setAdd(true)} style={{
        width:"100%",padding:"13px",borderRadius:12,
        background:T.rose,color:"#fff",fontSize:14,fontWeight:700,
        boxShadow:"0 2px 12px rgba(176,122,122,.3)"}}>+ Novo Produto</button>

      {add && <SkincareProdModal onClose={()=>setAdd(false)}
        onSave={p=>{setProdutos(ps=>[...ps,{id:Date.now(),...p}]);setAdd(false);}}/>}
      {edit && <SkincareProdModal produto={edit} onClose={()=>setEdit(null)}
        onSave={p=>{setProdutos(ps=>ps.map(x=>x.id===edit.id?{...x,...p}:x));setEdit(null);}}
        onDelete={()=>{setProdutos(ps=>ps.filter(x=>x.id!==edit.id));setEdit(null);}}/>}
    </>
  );
}

function SkincareProdModal({produto,onClose,onSave,onDelete}){
  const [form,setForm]=useState(produto||{nome:"",marca:"",categoria:"Sérum",
    inicio:now.toLocaleDateString("pt-BR"),fim:"",frequencia:"Manhã e noite",foto:null,obs:""});
  const fileRef=useRef();
  const handleFoto=async e=>{
    const f=e.target.files[0]; if(!f) return;
    const data=await compressImage(f,600,0.85);
    setForm(x=>({...x,foto:data}));
  };
  return (
    <Modal title={produto?"Editar Produto":"Novo Produto"} onClose={onClose}>
      <div style={{display:"flex",flexDirection:"column",gap:12}}>
        <button onClick={()=>fileRef.current.click()} style={{
          width:80,height:80,alignSelf:"center",borderRadius:14,
          background:T.roseBg,border:`2px dashed ${form.foto?T.rose:T.borderMd}`,
          display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden"}}>
          {form.foto ? (
            <img src={form.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
          ) : <span style={{fontSize:26}}>📷</span>}
        </button>
        <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={handleFoto}/>
        <Input label="Nome" value={form.nome} onChange={e=>setForm(f=>({...f,nome:e.target.value}))} placeholder="Ex: Sérum Vitamina C"/>
        <div style={{display:"flex",gap:10}}>
          <div style={{flex:1}}><Input label="Marca" value={form.marca} onChange={e=>setForm(f=>({...f,marca:e.target.value}))}/></div>
          <div style={{flex:1}}><Select label="Categoria" value={form.categoria} onChange={e=>setForm(f=>({...f,categoria:e.target.value}))} options={SKINCARE_CATEGORIAS}/></div>
        </div>
        <Input label="Frequência" value={form.frequencia} onChange={e=>setForm(f=>({...f,frequencia:e.target.value}))} placeholder="Ex: 3x/semana à noite"/>
        <div style={{display:"flex",gap:10}}>
          <div style={{flex:1}}><Input label="Início" value={form.inicio} onChange={e=>setForm(f=>({...f,inicio:e.target.value}))} placeholder="dd/mm/aaaa"/></div>
          <div style={{flex:1}}><Input label="Término" value={form.fim} onChange={e=>setForm(f=>({...f,fim:e.target.value}))} placeholder="(em uso)"/></div>
        </div>
        <div>
          <div style={{fontSize:11,color:T.textMute,fontWeight:700,marginBottom:5,letterSpacing:.3}}>OBSERVAÇÕES</div>
          <textarea value={form.obs} onChange={e=>setForm(f=>({...f,obs:e.target.value}))} rows={2}
            style={{width:"100%",padding:"10px 13px",borderRadius:10,
              border:`1px solid ${T.border}`,background:T.bgInput,fontSize:13,color:T.text,resize:"none"}}/>
        </div>
        <ModalActions onCancel={onClose} onSave={()=>onSave(form)} onDelete={onDelete} color={T.rose}/>
      </div>
    </Modal>
  );
}

