function TelaCasa({casaTarefas,setCasaTarefas,sitioProjetos,setSitioProjetos,onMenu}){
  const [tab,setTab]=useState("casa");
  return(
    <div style={{display:"flex",flexDirection:"column",height:"100%"}}>
      <AppHeader title="Casa & Sítio" onMenu={onMenu}/>
      <div style={{flex:1,overflowY:"auto",padding:"14px 16px 100px"}}>
        <MascoteHeader secao="casa" sub="Hoje e o sonho de amanhã"/>

        <div style={{display:"flex",background:T.bgInput,borderRadius:11,padding:3,gap:3,marginBottom:14}}>
          {[{id:"casa",l:"🏡 Casa"},{id:"sitio",l:"🌳 Sítio"}].map(t=>(
            <button key={t.id} onClick={()=>setTab(t.id)} style={{
              flex:1,padding:"7px 0",borderRadius:8,fontSize:13,fontWeight:700,
              background:tab===t.id?T.bgCard:"transparent",
              border:tab===t.id?`1px solid ${T.border}`:"none",
              color:tab===t.id?T.text:T.textMute}}>{t.l}</button>
          ))}
        </div>

        {tab==="casa" && <CasaTab tarefas={casaTarefas} setTarefas={setCasaTarefas}/>}
        {tab==="sitio" && <SitioTab projetos={sitioProjetos} setProjetos={setSitioProjetos}/>}
      </div>
    </div>
  );
}

function CasaTab({tarefas,setTarefas}){
  const [nova,setNova]=useState("");
  const [edit,setEdit]=useState(null);
  const toggle=id=>setTarefas(ts=>ts.map(t=>t.id===id?{...t,feita:!t.feita}:t));
  const deletar=id=>setTarefas(ts=>ts.filter(t=>t.id!==id));
  const add=()=>{if(!nova.trim())return;setTarefas(ts=>[...ts,{id:Date.now(),texto:nova.trim(),feita:false}]);setNova("");};

  const pendentes=tarefas.filter(t=>!t.feita);
  const concluidas=tarefas.filter(t=>t.feita);

  return (
    <>
      <div style={{display:"flex",gap:8,marginBottom:14}}>
        <input value={nova} onChange={e=>setNova(e.target.value)}
          onKeyDown={e=>e.key==="Enter"&&add()}
          placeholder="Adicionar tarefa…"
          style={{flex:1,padding:"11px 15px",borderRadius:11,
            border:`1px solid ${T.border}`,background:T.bgCard,fontSize:13,color:T.text}}/>
        <button onClick={add} style={{width:44,height:44,borderRadius:11,
          background:T.moss,color:"#fff",fontSize:20,
          display:"flex",alignItems:"center",justifyContent:"center",
          boxShadow:"0 2px 10px rgba(95,122,74,.35)"}}>+</button>
      </div>

      <div style={{fontSize:11,color:T.textMute,fontWeight:700,
        textTransform:"uppercase",letterSpacing:.8,marginBottom:8}}>
        Pendentes · {pendentes.length}
      </div>
      <Card style={{marginBottom:14}}>
        {pendentes.length===0 && (
          <div style={{padding:"16px",fontSize:13,color:T.textMute,textAlign:"center",fontStyle:"italic"}}>
            Casa em ordem 🏡
          </div>
        )}
        {pendentes.map((t,i)=>(
          <div key={t.id} style={{display:"flex",alignItems:"center",gap:11,
            padding:"11px 16px",borderBottom:i<pendentes.length-1?`1px solid ${T.border}`:"none"}}>
            <button onClick={()=>toggle(t.id)} style={{width:22,height:22,borderRadius:"50%",flexShrink:0,
              border:`2px solid ${T.borderMd}`,background:"transparent"}}/>
            <span style={{flex:1,fontSize:13,fontWeight:500}}>{t.texto}</span>
            <IconBtn icon="✏️" onClick={()=>setEdit({...t})}/>
            <IconBtn icon="🗑️" onClick={()=>deletar(t.id)}/>
          </div>
        ))}
      </Card>

      {concluidas.length>0 && (
        <>
          <div style={{fontSize:11,color:T.textMute,fontWeight:700,
            textTransform:"uppercase",letterSpacing:.8,marginBottom:8}}>
            Concluídas · {concluidas.length}
          </div>
          <Card>
            {concluidas.map((t,i)=>(
              <div key={t.id} style={{display:"flex",alignItems:"center",gap:11,
                padding:"11px 16px",opacity:.55,
                borderBottom:i<concluidas.length-1?`1px solid ${T.border}`:"none"}}>
              <button onClick={()=>toggle(t.id)} style={{width:22,height:22,borderRadius:"50%",flexShrink:0,
                border:`2px solid ${T.moss}`,background:T.moss,
                display:"flex",alignItems:"center",justifyContent:"center"}}>
                <svg width="11" height="9" viewBox="0 0 11 9" fill="none"><path d="M1 4L4 7.5L10 1" stroke="#fff" strokeWidth="2.2" strokeLinecap="round"/></svg>
              </button>
                <span style={{flex:1,fontSize:13,fontWeight:500,textDecoration:"line-through"}}>{t.texto}</span>
                <IconBtn icon="🗑️" onClick={()=>deletar(t.id)}/>
              </div>
            ))}
          </Card>
        </>
      )}

      {edit && (
        <Modal title="Editar Tarefa" onClose={()=>setEdit(null)}>
          <input value={edit.texto} onChange={e=>setEdit(m=>({...m,texto:e.target.value}))}
            style={{width:"100%",padding:"11px 14px",borderRadius:10,
              border:`1px solid ${T.border}`,background:T.bgInput,fontSize:14,marginBottom:12}}/>
          <ModalActions onCancel={()=>setEdit(null)}
            onSave={()=>{setTarefas(ts=>ts.map(t=>t.id===edit.id?{...t,texto:edit.texto}:t));setEdit(null);}}
            color={T.moss}/>
        </Modal>
      )}
    </>
  );
}

function SitioTab({projetos,setProjetos}){
  const [add,setAdd]=useState(false);
  const [edit,setEdit]=useState(null);

  const fases=["Planejamento","Em andamento","Concluído","Sonhos"];
  const categorias=["Reforma","Jardinagem","Pomar","Energia solar","Cercas","Paisagismo","Outros"];

  const toggle=id=>setProjetos(ps=>ps.map(p=>p.id===id?{...p,feita:!p.feita}:p));
  const deletar=id=>setProjetos(ps=>ps.filter(p=>p.id!==id));

  return (
    <>
      <Card style={{padding:"14px 16px",marginBottom:14,
        background:T.mossBg,border:`1px solid ${T.moss}22`}}>
        <div style={{display:"flex",alignItems:"center",gap:12}}>
          <img src={COW_ESTRELA} alt="" style={{width:50,height:50,objectFit:"contain"}}/>
          <div style={{flex:1}}>
            <div className="serif" style={{fontSize:18,fontWeight:700,color:T.moss}}>O sítio</div>
            <div style={{fontSize:12,color:T.textSub,fontStyle:"italic",marginTop:1}}>
              "{MASCOTES.casa.saudacoes[1]}" — Estrela
            </div>
            <div style={{fontSize:11,color:T.textMute,marginTop:4}}>
              {projetos.filter(p=>p.feita).length} de {projetos.length} marcos concluídos
            </div>
          </div>
        </div>
      </Card>

      {fases.map(f=>{
        const itens=projetos.filter(p=>p.fase===f);
        if(itens.length===0) return null;
        return (
          <div key={f} style={{marginBottom:14}}>
            <div style={{fontSize:11,color:T.moss,fontWeight:700,
              textTransform:"uppercase",letterSpacing:.8,marginBottom:8}}>
              {f} · {itens.length}
            </div>
            <div style={{display:"flex",flexDirection:"column",gap:8}}>
              {itens.map(p=>(
                <Card key={p.id} style={{padding:"12px 14px",opacity:p.feita?.65:1}}>
                  <div style={{display:"flex",alignItems:"center",gap:10}}>
                    <button onClick={()=>toggle(p.id)} style={{width:22,height:22,borderRadius:"50%",flexShrink:0,
                      border:`2px solid ${p.feita?T.moss:T.borderMd}`,
                      background:p.feita?T.moss:"transparent",
                      display:"flex",alignItems:"center",justifyContent:"center"}}>
                      {p.feita&&<svg width="11" height="9" viewBox="0 0 11 9" fill="none"><path d="M1 4L4 7.5L10 1" stroke="#fff" strokeWidth="2.2" strokeLinecap="round"/></svg>}
                    </button>
                    <span style={{flex:1,fontSize:13,fontWeight:600,textDecoration:p.feita?"line-through":"none"}}>{p.texto}</span>
                    {p.categoria&&<Pill label={p.categoria} color={T.moss} bg={T.mossBg}/>}
                    <IconBtn icon="✏️" onClick={()=>setEdit({...p})}/>
                    <IconBtn icon="🗑️" onClick={()=>deletar(p.id)}/>
                  </div>
                  {p.fotos&&p.fotos.length>0 && (
                    <div style={{display:"flex",gap:6,marginTop:10,overflowX:"auto"}}>
                      {p.fotos.map((foto,i)=>(
                        <img key={i} src={foto} alt="" style={{width:64,height:64,borderRadius:8,objectFit:"cover",flexShrink:0}}/>
                      ))}
                    </div>
                  )}
                </Card>
              ))}
            </div>
          </div>
        );
      })}

      <button onClick={()=>setAdd(true)} style={{
        width:"100%",padding:"13px",borderRadius:12,
        background:T.moss,color:"#fff",fontSize:14,fontWeight:700,
        boxShadow:"0 2px 12px rgba(95,122,74,.3)"}}>+ Novo Projeto</button>

      {add && <ProjetoSitioModal categorias={categorias} fases={fases} onClose={()=>setAdd(false)}
        onSave={p=>{setProjetos(ps=>[...ps,{id:Date.now(),...p,feita:false}]);setAdd(false);}}/>}
      {edit && <ProjetoSitioModal projeto={edit} categorias={categorias} fases={fases}
        onClose={()=>setEdit(null)}
        onSave={p=>{setProjetos(ps=>ps.map(x=>x.id===edit.id?{...x,...p}:x));setEdit(null);}}
        onDelete={()=>{setProjetos(ps=>ps.filter(x=>x.id!==edit.id));setEdit(null);}}/>}
    </>
  );
}

function ProjetoSitioModal({projeto,categorias,fases,onClose,onSave,onDelete}){
  const [form,setForm]=useState(projeto||{texto:"",fase:"Planejamento",categoria:"Outros",fotos:[]});
  const fileRef=useRef();
  const addFoto=async e=>{
    const f=e.target.files[0]; if(!f) return;
    const data=await compressImage(f,900,0.85);
    setForm(x=>({...x,fotos:[...(x.fotos||[]),data]}));
  };
  const removerFoto=i=>setForm(x=>({...x,fotos:x.fotos.filter((_,idx)=>idx!==i)}));

  return (
    <Modal title={projeto?"Editar Projeto":"Novo Projeto"} onClose={onClose}>
      <div style={{display:"flex",flexDirection:"column",gap:12}}>
        <Input label="Descrição" value={form.texto} onChange={e=>setForm(f=>({...f,texto:e.target.value}))}/>
        <div style={{display:"flex",gap:10}}>
          <div style={{flex:1}}><Select label="Fase" value={form.fase} onChange={e=>setForm(f=>({...f,fase:e.target.value}))} options={fases}/></div>
          <div style={{flex:1}}><Select label="Categoria" value={form.categoria} onChange={e=>setForm(f=>({...f,categoria:e.target.value}))} options={categorias}/></div>
        </div>
        <div>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:5}}>
            <div style={{fontSize:11,color:T.textMute,fontWeight:700,letterSpacing:.3}}>FOTOS DA EVOLUÇÃO</div>
            <button onClick={()=>fileRef.current.click()} style={{fontSize:11,fontWeight:700,color:T.moss}}>+ Foto</button>
          </div>
          <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={addFoto}/>
          {form.fotos&&form.fotos.length>0 && (
            <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
              {form.fotos.map((foto,i)=>(
                <div key={i} style={{position:"relative",width:70,height:70}}>
                  <img src={foto} alt="" style={{width:"100%",height:"100%",borderRadius:8,objectFit:"cover"}}/>
                  <button onClick={()=>removerFoto(i)} style={{position:"absolute",top:-4,right:-4,
                    width:20,height:20,borderRadius:"50%",background:T.danger,color:"#fff",fontSize:11,
                    display:"flex",alignItems:"center",justifyContent:"center"}}>×</button>
                </div>
              ))}
            </div>
          )}
        </div>
        <ModalActions onCancel={onClose} onSave={()=>onSave(form)} onDelete={onDelete} color={T.moss}/>
      </div>
    </Modal>
  );
}

/* ════════════════════════════════════════════════════════════════════════════
   TELA MEMÓRIAS — Timeline visual da vida
═══════════════════════════════════════════════════════════════════════════ */
function TelaMemorias({pets,looks,makes,skDiario,sitioProjetos,onMenu,onNav}){
  // Agregar tudo
  const memorias=useMemo(()=>{
    const all=[];
    pets.forEach(p=>{
      (p.galeria||[]).forEach(g=>{
        const d=parseDate(g.data);
        if(d) all.push({data:d,dataStr:g.data,foto:g.foto,tipo:"Pet",sub:p.nome,cor:T.blue,bg:T.blueBg,onClick:()=>onNav("pets")});
      });
    });
    looks.forEach(l=>{
      const d=parseDate(l.data);
      if(d&&l.foto) all.push({data:d,dataStr:l.data,foto:l.foto,tipo:"Look",sub:l.titulo||l.ocasiao,cor:T.sand,bg:T.sandBg,onClick:()=>onNav("closet")});
    });
    makes.forEach(m=>{
      const d=parseDate(m.data);
      if(d&&m.foto) all.push({data:d,dataStr:m.data,foto:m.foto,tipo:"Make",sub:m.titulo,cor:T.rose,bg:T.roseBg,onClick:()=>onNav("beauty")});
    });
    skDiario.forEach(s=>{
      const d=parseDate(s.data);
      if(d&&s.fotoFrontal) all.push({data:d,dataStr:s.data,foto:s.fotoFrontal,tipo:"Pele",sub:"Diário",cor:T.rose,bg:T.roseBg,onClick:()=>onNav("beauty")});
    });
    sitioProjetos.forEach(p=>{
      (p.fotos||[]).forEach((foto,i)=>{
        all.push({data:new Date(now.getTime()-i*86400000),dataStr:"Sítio",foto,tipo:"Sítio",sub:p.texto,cor:T.moss,bg:T.mossBg,onClick:()=>onNav("casa")});
      });
    });
    return all.sort((a,b)=>b.data-a.data);
  },[pets,looks,makes,skDiario,sitioProjetos]);

  // Agrupar por "tempo passado"
  const grupos=useMemo(()=>{
    const g={};
    memorias.forEach(m=>{
      const dias=Math.floor((now-m.data)/86400000);
      let label;
      if(dias<=7) label="Esta semana";
      else if(dias<=30) label="Há 30 dias";
      else if(dias<=90) label="Há 3 meses";
      else if(dias<=180) label="Há 6 meses";
      else if(dias<=365) label="Há 1 ano";
      else label="Mais de 1 ano";
      if(!g[label]) g[label]=[];
      g[label].push(m);
    });
    return g;
  },[memorias]);

  const ordemGrupos=["Esta semana","Há 30 dias","Há 3 meses","Há 6 meses","Há 1 ano","Mais de 1 ano"];

  return (
    <div style={{display:"flex",flexDirection:"column",height:"100%"}}>
      <AppHeader title="Memórias" onMenu={onMenu}/>
      <div style={{flex:1,overflowY:"auto",padding:"14px 16px 100px"}}>
        <MascoteHeader secao="memorias" sub="Sua linha do tempo"/>

        {memorias.length===0 ? (
          <Card style={{padding:"30px 20px",textAlign:"center"}}>
            <img src={COW_MIMOSA} alt="" style={{width:80,height:80,objectFit:"contain",marginBottom:10}}/>
            <div className="serif" style={{fontSize:16,fontWeight:700,marginBottom:4}}>
              "Memórias são tesouros silenciosos"
            </div>
            <div style={{fontSize:12,color:T.textMute,fontStyle:"italic",marginBottom:14}}>— Mimosa</div>
            <div style={{fontSize:12,color:T.textMute,lineHeight:1.5}}>
              Registre fotos dos pets, looks, makes e pele.<br/>Aqui elas viram sua linha do tempo.
            </div>
          </Card>
        ) : (
          <>
            <Card style={{padding:"12px 14px",marginBottom:14,background:T.lavBg,border:`1px solid ${T.lav}22`}}>
              <div style={{display:"flex",alignItems:"baseline",gap:14}}>
                <div>
                  <div className="serif" style={{fontSize:24,fontWeight:700,color:T.lav}}>{memorias.length}</div>
                  <div style={{fontSize:10,color:T.textMute,fontWeight:600}}>memórias</div>
                </div>
                <div>
                  <div className="serif" style={{fontSize:24,fontWeight:700,color:T.lav}}>
                    {new Set(memorias.map(m=>m.tipo)).size}
                  </div>
                  <div style={{fontSize:10,color:T.textMute,fontWeight:600}}>categorias</div>
                </div>
              </div>
            </Card>

            {ordemGrupos.filter(g=>grupos[g]).map(grupo=>(
              <div key={grupo} style={{marginBottom:18}}>
                <div className="serif" style={{fontSize:17,fontWeight:700,color:T.lav,marginBottom:10,letterSpacing:-.3}}>
                  {grupo}
                </div>
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:6}}>
                  {grupos[grupo].slice(0,12).map((m,i)=>(
                    <button key={i} onClick={m.onClick} style={{
                      aspectRatio:"1",borderRadius:10,overflow:"hidden",
                      border:`1px solid ${T.border}`,position:"relative",padding:0,background:"none"}}>
                      <img src={m.foto} alt="" style={{width:"100%",height:"100%",objectFit:"cover",display:"block"}}/>
                      <div style={{position:"absolute",bottom:0,left:0,right:0,
                        background:"linear-gradient(transparent, rgba(0,0,0,0.7))",
                        padding:"12px 6px 4px",color:"#fff",textAlign:"left"}}>
                        <div style={{fontSize:9,fontWeight:700,opacity:.85}}>{m.tipo}</div>
                      </div>
                    </button>
                  ))}
                </div>
              </div>
            ))}
          </>
        )}
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════════════════
   ROOT
═══════════════════════════════════════════════════════════════════════════ */
export default function ZenCow(){
  const [splash,setSplash]=useState(true);
  const [tela,setTela]=useState("hoje");
  const [drawer,setDrawer]=useState(false);
  const [moreSheet,setMoreSheet]=useState(false);

  const [agenda,setAgenda]=useState(AGENDA_INIT);
  const [pets,setPets]=useState(PETS_INIT);
  const [petOpenId,setPetOpenId]=useState(null);
  const [closetPecas,setClosetPecas]=useState(CLOSET_PECAS_INIT);
  const [closetLooks,setClosetLooks]=useState(CLOSET_LOOKS_INIT);
  const [beautyProdutos,setBeautyProdutos]=useState(BEAUTY_PRODUTOS_INIT);
  const [beautyMakes,setBeautyMakes]=useState(BEAUTY_MAKES_INIT);
  const [skProdutos,setSkProdutos]=useState(SKINCARE_PRODUTOS_INIT);
  const [skDiario,setSkDiario]=useState(SKINCARE_DIARIO_INIT);
  const [casaTarefas,setCasaTarefas]=useState(CASA_TAREFAS_INIT);
  const [sitioProjetos,setSitioProjetos]=useState(CASA_PROJETOS_INIT);
  const [loaded,setLoaded]=useState(false);

  // ── Load do Supabase no mount ──────────────────────────────────────────
  useEffect(()=>{
    let cancelled=false;
    (async()=>{
      try{
        const data = await loadOne("zencow_state");
        if(cancelled||!data) { setLoaded(true); return; }
        if(data.agenda) setAgenda(data.agenda);
        if(data.pets) setPets(data.pets);
        if(data.closet_pecas) setClosetPecas(data.closet_pecas);
        if(data.closet_looks) setClosetLooks(data.closet_looks);
        if(data.beauty_produtos) setBeautyProdutos(data.beauty_produtos);
        if(data.beauty_makes) setBeautyMakes(data.beauty_makes);
        if(data.sk_produtos) setSkProdutos(data.sk_produtos);
        if(data.sk_diario) setSkDiario(data.sk_diario);
        if(data.casa_tarefas) setCasaTarefas(data.casa_tarefas);
        if(data.sitio_projetos) setSitioProjetos(data.sitio_projetos);
      } catch(e){ console.warn("Load falhou, usando defaults:",e); }
      finally { if(!cancelled) setLoaded(true); }
    })();
    return ()=>{cancelled=true;};
  },[]);

  // ── Auto-save (debounced 1.2s) ─────────────────────────────────────────
  useEffect(()=>{
    if(!loaded) return; // não salva antes do load inicial
    const t=setTimeout(()=>{
      saveOne("zencow_state",{
        agenda, pets,
        closet_pecas:closetPecas, closet_looks:closetLooks,
        beauty_produtos:beautyProdutos, beauty_makes:beautyMakes,
        sk_produtos:skProdutos, sk_diario:skDiario,
        casa_tarefas:casaTarefas, sitio_projetos:sitioProjetos,
      });
    },1200);
    return ()=>clearTimeout(t);
  },[loaded,agenda,pets,closetPecas,closetLooks,beautyProdutos,beautyMakes,
     skProdutos,skDiario,casaTarefas,sitioProjetos]);

  const navTo=t=>{setTela(t); if(t==="pets") setPetOpenId(null);};
  const navToPet=id=>{setTela("pets"); setPetOpenId(id);};
  const props={onMenu:()=>setDrawer(true)};

  const renderTela=()=>{
    switch(tela){
      case "hoje":
        return <TelaHoje agenda={agenda} pets={pets}
          looks={closetLooks} makes={beautyMakes} skDiario={skDiario} skProdutos={skProdutos}
          sitioProjetos={sitioProjetos} casaTarefas={casaTarefas}
          onNavPet={navToPet} onNav={navTo} nomeUsuario="Drika" {...props}/>;
      case "agenda":
        return <TelaAgenda agenda={agenda} setAgenda={setAgenda} {...props}/>;
      case "pets":
        return <TelaPets pets={pets} setPets={setPets}
          petOpenId={petOpenId} setPetOpenId={setPetOpenId} {...props}/>;
      case "closet":
        return <TelaCloset pecas={closetPecas} setPecas={setClosetPecas}
          looks={closetLooks} setLooks={setClosetLooks} {...props}/>;
      case "beauty":
        return <TelaBeauty produtos={beautyProdutos} setProdutos={setBeautyProdutos}
          makes={beautyMakes} setMakes={setBeautyMakes}
          skProdutos={skProdutos} setSkProdutos={setSkProdutos}
          skDiario={skDiario} setSkDiario={setSkDiario} {...props}/>;
      case "casa":
        return <TelaCasa casaTarefas={casaTarefas} setCasaTarefas={setCasaTarefas}
          sitioProjetos={sitioProjetos} setSitioProjetos={setSitioProjetos} {...props}/>;
      case "memorias":
        return <TelaMemorias pets={pets} looks={closetLooks} makes={beautyMakes}
          skDiario={skDiario} sitioProjetos={sitioProjetos} onNav={navTo} {...props}/>;
      default: return null;
    }
  };

  return(
    <>
      <GS/>
      <div style={{width:"100%",maxWidth:430,margin:"0 auto",
        height:"100dvh",background:T.bgPage,
        display:"flex",flexDirection:"column",
        overflow:"hidden",fontFamily:"'Nunito',sans-serif",position:"relative"}}>
        {splash?(
          <Splash onDone={()=>setSplash(false)}/>
        ):(
          <>
            {drawer && <Drawer onClose={()=>setDrawer(false)} onNav={navTo}/>}
            {moreSheet && <MoreSheet onClose={()=>setMoreSheet(false)} onNav={navTo} active={tela}/>}
            <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden",minHeight:0}}>
              {renderTela()}
            </div>
            <NavBar active={tela} onSelect={navTo} openMore={()=>setMoreSheet(true)}/>
          </>
        )}
      </div>
    </>
  );
}
